'use client';
import { useState, useEffect } from 'react';
import Link from 'next/link';
import { useRouter, usePathname } from 'next/navigation';
import { api } from '@/lib/api';

export default function Navbar() {
  const router = useRouter();
  const pathname = usePathname();
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [darkMode, setDarkMode] = useState(false); // Default is false (light mode)

  useEffect(() => {
    // Check authentication
    const token = localStorage.getItem('token');
    const userData = localStorage.getItem('user');

    setIsAuthenticated(!!token);
    if (userData) {
      try {
        setUser(JSON.parse(userData));
      } catch {
        // Ignore parse errors
      }
    }

    // Load user profile if authenticated
    if (token) {
      loadUserProfile();
    }

    // Check dark mode preference - only from localStorage (user's explicit choice)
    // Default is FALSE (light mode) - only activate if user explicitly enabled it
    const savedDarkMode = localStorage.getItem('darkMode') === 'true';
    setDarkMode(savedDarkMode);
    // Only apply dark mode if user explicitly enabled it, otherwise ensure light mode
    if (savedDarkMode) {
      applyDarkMode(true);
    } else {
      applyDarkMode(false); // Explicitly set light mode
    }
  }, []);

  const loadUserProfile = async () => {
    try {
      const userData = await api.getUserProfile();
      setUser(userData);
      localStorage.setItem('user', JSON.stringify(userData));
    } catch (err) {
      console.error('Error loading user profile:', err);
    }
  };

  const applyDarkMode = (enabled) => {
    if (enabled) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  };

  const toggleDarkMode = () => {
    const newDarkMode = !darkMode;
    setDarkMode(newDarkMode);
    localStorage.setItem('darkMode', newDarkMode.toString());
    applyDarkMode(newDarkMode);
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setIsAuthenticated(false);
    setUser(null);
    router.push('/');
  };

  const isActive = (path) => pathname === path;

  return (
    <nav className="bg-white dark:bg-gray-800 shadow-md border-b border-gray-200 dark:border-gray-700">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          {/* Logo */}
          <Link href="/" className="flex items-center space-x-2">
            <span className="text-2xl font-bold text-orange-600 dark:text-orange-400">
              ≡ƒì│ TastyHub
            </span>
          </Link>

          {/* Navigation Links (Desktop) */}
          <div className="hidden md:flex items-center space-x-6">
            <Link
              href="/"
              className={`px-3 py-2 rounded-md text-sm font-medium transition ${isActive('/')
                ? 'text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-900'
                : 'text-gray-700 dark:text-gray-300 hover:text-orange-600 dark:hover:text-orange-400'
                }`}
            >
              Home
            </Link>
            <Link
              href="/recipes"
              className={`px-3 py-2 rounded-md text-sm font-medium transition ${isActive('/recipes')
                ? 'text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-900'
                : 'text-gray-700 dark:text-gray-300 hover:text-orange-600 dark:hover:text-orange-400'
                }`}
            >
              Recipes
            </Link>
            <Link
              href="/about"
              className={`px-3 py-2 rounded-md text-sm font-medium transition ${isActive('/about')
                ? 'text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-900'
                : 'text-gray-700 dark:text-gray-300 hover:text-orange-600 dark:hover:text-orange-400'
                }`}
            >
              About
            </Link>

            {isAuthenticated ? (
              <>
                <Link
                  href="/my-recipes"
                  className={`px-3 py-2 rounded-md text-sm font-medium transition ${isActive('/my-recipes')
                    ? 'text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-900'
                    : 'text-gray-700 dark:text-gray-300 hover:text-orange-600 dark:hover:text-orange-400'
                    }`}
                >
                  My Recipes
                </Link>
                <Link
                  href="/favorites"
                  className={`px-3 py-2 rounded-md text-sm font-medium transition ${isActive('/favorites')
                    ? 'text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-900'
                    : 'text-gray-700 dark:text-gray-300 hover:text-orange-600 dark:hover:text-orange-400'
                    }`}
                >
                  Favorites
                </Link>
                <Link
                  href="/profile"
                  className={`px-3 py-2 rounded-md text-sm font-medium transition ${isActive('/profile')
                    ? 'text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-900'
                    : 'text-gray-700 dark:text-gray-300 hover:text-orange-600 dark:hover:text-orange-400'
                    }`}
                >
                  Profile
                </Link>
                <Link
                  href="/settings"
                  className={`px-3 py-2 rounded-md text-sm font-medium transition ${isActive('/settings')
                    ? 'text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-900'
                    : 'text-gray-700 dark:text-gray-300 hover:text-orange-600 dark:hover:text-orange-400'
                    }`}
                >
                  Settings
                </Link>

                {/* Dark Mode Toggle */}
                <button
                  onClick={toggleDarkMode}
                  className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition"
                  title={darkMode ? 'Switch to light mode' : 'Switch to dark mode'}
                >
                  {darkMode ? 'ΓÿÇ∩╕Å' : '≡ƒîÖ'}
                </button>

                {/* Profile Picture / User Menu */}
                <div className="flex items-center gap-3">
                  <Link href="/profile" className="flex items-center gap-2">
                    <div className="w-8 h-8 rounded-full bg-orange-100 dark:bg-orange-900 flex items-center justify-center overflow-hidden border-2 border-orange-300 dark:border-orange-700 relative">
                      {user?.profilePicture ? (
                        <img
                          src={user.profilePicture}
                          alt={user.username || 'User'}
                          className="w-full h-full object-cover"
                          onError={(e) => {
                            e.target.style.display = 'none';
                            e.target.nextSibling.style.display = 'flex';
                          }}
                        />
                      ) : null}
                      <span className={`text-sm font-bold text-orange-600 dark:text-orange-400 absolute inset-0 flex items-center justify-center ${user?.profilePicture ? 'hidden' : 'flex'}`}>
                        {user?.username?.charAt(0).toUpperCase() || 'U'}
                      </span>
                    </div>
                    <span className="hidden lg:inline text-sm font-medium text-gray-700 dark:text-gray-300">
                      {user?.username || 'User'}
                    </span>
                  </Link>
                  <button
                    onClick={handleLogout}
                    className="px-4 py-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition text-sm font-medium"
                  >
                    Logout
                  </button>
                </div>
              </>
            ) : (
              <>
                {/* Dark Mode Toggle */}
                <button
                  onClick={toggleDarkMode}
                  className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition"
                  title={darkMode ? 'Switch to light mode' : 'Switch to dark mode'}
                >
                  {darkMode ? 'ΓÿÇ∩╕Å' : '≡ƒîÖ'}
                </button>
                <Link
                  href="/login"
                  className="px-4 py-2 text-gray-700 dark:text-gray-300 hover:text-orange-600 dark:hover:text-orange-400 transition text-sm font-medium"
                >
                  Login
                </Link>
                <Link
                  href="/register"
                  className="px-4 py-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition text-sm font-medium"
                >
                  Sign Up
                </Link>
              </>
            )}
          </div>

          {/* Mobile menu button */}
          <div className="md:hidden flex items-center gap-4">
            {/* Dark Mode Toggle (Mobile) */}
            <button
              onClick={toggleDarkMode}
              className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition"
              title={darkMode ? 'Switch to light mode' : 'Switch to dark mode'}
            >
              {darkMode ? 'ΓÿÇ∩╕Å' : '≡ƒîÖ'}
            </button>

            <button
              className="text-gray-700 dark:text-gray-300 hover:text-orange-600 dark:hover:text-orange-400 p-2"
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            >
              <span className="text-2xl">Γÿ░</span>
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isMobileMenuOpen && (
        <div className="md:hidden bg-white dark:bg-gray-800 border-t border-gray-200 dark:border-gray-700 absolute top-16 left-0 right-0 shadow-lg z-50 max-h-[calc(100vh-4rem)] overflow-y-auto">
          <div className="px-4 pt-4 pb-6 space-y-1">
            {isAuthenticated && (
              <>
                <div className="flex items-center gap-3 px-3 mb-4">
                  <div className="w-10 h-10 rounded-full bg-orange-100 dark:bg-orange-900 flex items-center justify-center overflow-hidden border-2 border-orange-300 dark:border-orange-700 relative flex-shrink-0">
                    {user?.profilePicture ? (
                      <img
                        src={user.profilePicture}
                        alt={user.username || 'User'}
                        className="w-full h-full object-cover"
                        onError={(e) => {
                          e.target.style.display = 'none';
                          e.target.nextSibling.style.display = 'flex';
                        }}
                      />
                    ) : null}
                    <span className={`text-sm font-bold text-orange-600 dark:text-orange-400 absolute inset-0 flex items-center justify-center ${user?.profilePicture ? 'hidden' : 'flex'}`}>
                      {user?.username?.charAt(0).toUpperCase() || 'U'}
                    </span>
                  </div>
                  <div className="flex flex-col">
                    <span className="font-semibold text-gray-900 dark:text-white">
                      {user?.username || 'User'}
                    </span>
                    <span className="text-xs text-gray-500 dark:text-gray-400">
                      Logged in
                    </span>
                  </div>
                </div>
                <div className="border-t border-gray-200 dark:border-gray-700 my-2"></div>
              </>
            )}

            <Link
              href="/"
              className={`flex items-center gap-3 px-3 py-3 rounded-lg text-base font-medium transition ${isActive('/')
                ? 'bg-orange-50 dark:bg-orange-900/20 text-orange-600 dark:text-orange-400'
                : 'text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700'}`}
              onClick={() => setIsMobileMenuOpen(false)}
            >
              <span>≡ƒÅá</span> Home
            </Link>
            <Link
              href="/recipes"
              className={`flex items-center gap-3 px-3 py-3 rounded-lg text-base font-medium transition ${isActive('/recipes')
                ? 'bg-orange-50 dark:bg-orange-900/20 text-orange-600 dark:text-orange-400'
                : 'text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700'}`}
              onClick={() => setIsMobileMenuOpen(false)}
            >
              <span>≡ƒôû</span> Recipes
            </Link>
            <Link
              href="/about"
              className={`flex items-center gap-3 px-3 py-3 rounded-lg text-base font-medium transition ${isActive('/about')
                ? 'bg-orange-50 dark:bg-orange-900/20 text-orange-600 dark:text-orange-400'
                : 'text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700'}`}
              onClick={() => setIsMobileMenuOpen(false)}
            >
              <span>Γä╣∩╕Å</span> About
            </Link>

            {isAuthenticated ? (
              <>
                <div className="space-y-1 mt-2">
                  <Link
                    href="/my-recipes"
                    className={`flex items-center gap-3 px-3 py-3 rounded-lg text-base font-medium transition ${isActive('/my-recipes')
                      ? 'bg-orange-50 dark:bg-orange-900/20 text-orange-600 dark:text-orange-400'
                      : 'text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700'}`}
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    <span>≡ƒæ¿ΓÇì≡ƒì│</span> My Recipes
                  </Link>
                  <Link
                    href="/favorites"
                    className={`flex items-center gap-3 px-3 py-3 rounded-lg text-base font-medium transition ${isActive('/favorites')
                      ? 'bg-orange-50 dark:bg-orange-900/20 text-orange-600 dark:text-orange-400'
                      : 'text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700'}`}
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    <span>Γ¥ñ∩╕Å</span> Favorites
                  </Link>
                  <Link
                    href="/profile"
                    className={`flex items-center gap-3 px-3 py-3 rounded-lg text-base font-medium transition ${isActive('/profile')
                      ? 'bg-orange-50 dark:bg-orange-900/20 text-orange-600 dark:text-orange-400'
                      : 'text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700'}`}
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    <span>≡ƒæñ</span> Profile
                  </Link>
                  <Link
                    href="/settings"
                    className={`flex items-center gap-3 px-3 py-3 rounded-lg text-base font-medium transition ${isActive('/settings')
                      ? 'bg-orange-50 dark:bg-orange-900/20 text-orange-600 dark:text-orange-400'
                      : 'text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700'}`}
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    <span>ΓÜÖ∩╕Å</span> Settings
                  </Link>
                  <button
                    onClick={() => {
                      handleLogout();
                      setIsMobileMenuOpen(false);
                    }}
                    className="w-full flex items-center gap-3 px-3 py-3 rounded-lg text-base font-medium text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 transition"
                  >
                    <span>≡ƒÜ¬</span> Logout
                  </button>
                </div>
              </>
            ) : (
              <div className="pt-4 mt-2 border-t border-gray-200 dark:border-gray-700 flex flex-col gap-3">
                <Link
                  href="/login"
                  className="block w-full px-4 py-3 rounded-lg text-base font-medium text-center text-gray-700 dark:text-gray-300 border border-gray-300 dark:border-gray-600 hover:bg-gray-50 dark:hover:bg-gray-700 transition"
                  onClick={() => setIsMobileMenuOpen(false)}
                >
                  Login
                </Link>
                <Link
                  href="/register"
                  className="block w-full px-4 py-3 rounded-lg text-base font-medium text-center text-white bg-orange-500 hover:bg-orange-600 shadow-md transition"
                  onClick={() => setIsMobileMenuOpen(false)}
                >
                  Sign Up
                </Link>
              </div>
            )}
          </div>
        </div>
      )}
    </nav>
  );
}


// End of Navbar component

'use client';
import { useEffect, useRef } from 'react';

export default function ParticlesBackground() {
    const canvasRef = useRef(null);
    const containerRef = useRef(null);

    useEffect(() => {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        let animationFrameId;
        let particles = [];
        let mouse = { x: null, y: null, radius: 150 };

        const handleResize = () => {
            if (containerRef.current && canvas) {
                canvas.width = containerRef.current.offsetWidth;
                canvas.height = containerRef.current.offsetHeight;
                initParticles();
            }
        };

        const handleMouseMove = (event) => {
            if (containerRef.current) {
                const rect = containerRef.current.getBoundingClientRect();
                mouse.x = event.clientX - rect.left;
                mouse.y = event.clientY - rect.top;
            }
        };

        const handleMouseLeave = () => {
            mouse.x = null;
            mouse.y = null;
        };

        class Particle {
            constructor() {
                this.x = Math.random() * canvas.width;
                this.y = Math.random() * canvas.height;
                this.vx = (Math.random() - 0.5) * 0.5; // Velocity X
                this.vy = (Math.random() - 0.5) * 0.5; // Velocity Y
                this.size = Math.random() * 2 + 1;
                this.baseX = this.x;
                this.baseY = this.y;
                this.density = (Math.random() * 30) + 1;
            }

            update() {
                // Mouse interaction
                if (mouse.x != null) {
                    let dx = mouse.x - this.x;
                    let dy = mouse.y - this.y;
                    let distance = Math.sqrt(dx * dx + dy * dy);
                    let forceDirectionX = dx / distance;
                    let forceDirectionY = dy / distance;
                    let maxDistance = mouse.radius;
                    let force = (maxDistance - distance) / maxDistance;
                    let directionX = forceDirectionX * force * this.density;
                    let directionY = forceDirectionY * force * this.density;

                    if (distance < mouse.radius) {
                        this.x -= directionX;
                        this.y -= directionY;
                    } else {
                        if (this.x !== this.baseX) {
                            let dx = this.x - this.baseX;
                            this.x -= dx / 10;
                        }
                        if (this.y !== this.baseY) {
                            let dy = this.y - this.baseY;
                            this.y -= dy / 10;
                        }
                    }
                }

                // Movement
                this.x += this.vx;
                this.y += this.vy;

                // Bounce off edges
                if (this.x < 0 || this.x > canvas.width) this.vx = -this.vx;
                if (this.y < 0 || this.y > canvas.height) this.vy = -this.vy;
            }

            draw() {
                ctx.fillStyle = 'rgba(249, 115, 22, 0.5)'; // Orange-500 with opacity
                ctx.beginPath();
                ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
                ctx.closePath();
                ctx.fill();
            }
        }

        const initParticles = () => {
            particles = [];
            // Responsive particle count
            const particleCount = window.innerWidth < 768 ? 40 : 80;
            for (let i = 0; i < particleCount; i++) {
                particles.push(new Particle());
            }
        };

        const animate = () => {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Draw lines
            for (let a = 0; a < particles.length; a++) {
                for (let b = a; b < particles.length; b++) {
                    let dx = particles[a].x - particles[b].x;
                    let dy = particles[a].y - particles[b].y;
                    let distance = Math.sqrt(dx * dx + dy * dy);

                    if (distance < 100) {
                        ctx.strokeStyle = `rgba(249, 115, 22, ${1 - distance / 100})`; // Fade out line
                        ctx.lineWidth = 1;
                        ctx.beginPath();
                        ctx.moveTo(particles[a].x, particles[a].y);
                        ctx.lineTo(particles[b].x, particles[b].y);
                        ctx.stroke();
                    }
                }
            }

            // Update and draw particles
            particles.forEach(particle => {
                particle.update();
                particle.draw();
            });

            animationFrameId = requestAnimationFrame(animate);
        };

        // Initialize
        window.addEventListener('resize', handleResize);
        if (containerRef.current) {
            containerRef.current.addEventListener('mousemove', handleMouseMove);
            containerRef.current.addEventListener('mouseleave', handleMouseLeave);
        }

        handleResize();
        animate();

        return () => {
            window.removeEventListener('resize', handleResize);
            if (containerRef.current) {
                containerRef.current.removeEventListener('mousemove', handleMouseMove);
                containerRef.current.removeEventListener('mouseleave', handleMouseLeave);
            }
            cancelAnimationFrame(animationFrameId);
        };
    }, []);

    return (
        <div ref={containerRef} className="absolute inset-0 z-0 overflow-hidden pointer-events-auto">
            <canvas ref={canvasRef} className="block w-full h-full" />
        </div>
    );
}

'use client';
import Link from "next/link";
import Image from "next/image";
import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { api } from "@/lib/api";

export default function RecipeCard({ recipe }) {
    const router = useRouter();
    const [isFavorited, setIsFavorited] = useState(!!recipe.isFavorited);
    // We don't need loading state for optimistic UI, but keeping it for compatibility if needed later
    const [favoriteLoading, setFavoriteLoading] = useState(false);

    useEffect(() => {
        setIsFavorited(!!recipe.isFavorited);
    }, [recipe.isFavorited]);

    const handleFavoriteToggle = async (event) => {
        event.preventDefault();
        event.stopPropagation();

        const token = localStorage.getItem('token');
        if (!token) {
            router.push('/login?redirect=/recipes');
            return;
        }

        // Optimistic UI update: Toggle immediately
        const previousState = isFavorited;
        setIsFavorited(!previousState);

        try {
            // Perform API call in background
            await api.favoriteRecipe(recipe.id);
        } catch (error) {
            console.error('Error toggling favorite:', error);
            // Revert state on error
            setIsFavorited(previousState);
            alert(error.message || 'Failed to update favorite');
        }
    };

    const [imgSrc, setImgSrc] = useState(recipe.image_url || recipe.imageUrl || '/placeholder-recipe.png');
    const [imgError, setImgError] = useState(false);

    useEffect(() => {
        setImgSrc(recipe.image_url || recipe.imageUrl || '/placeholder-recipe.png');
        setImgError(false);
    }, [recipe.image_url, recipe.imageUrl]);

    // ... handleFavoriteToggle

    return (
        <Link
            href={`/recipes/${recipe.id}`}
            className="bg-white dark:bg-gray-800 rounded-2xl shadow hover:shadow-lg transition overflow-hidden block cursor-pointer group h-full flex flex-col"
        >
            <div className="relative overflow-hidden h-48 w-full bg-gray-100 dark:bg-gray-700">
                {!imgError ? (
                    <Image
                        src={imgSrc}
                        alt={recipe.title}
                        fill
                        sizes="(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 33vw"
                        className="object-cover transition-transform duration-300 group-hover:scale-105"
                        priority={false}
                        onError={() => setImgError(true)}
                    />
                ) : (
                    <img
                        src={imgSrc}
                        alt={recipe.title}
                        className="w-full h-full object-cover transition-transform duration-300 group-hover:scale-105"
                        onError={(e) => {
                            e.target.onerror = null;
                            e.target.src = '/placeholder-recipe.png';
                        }}
                    />
                )}
                <button
                    onClick={handleFavoriteToggle}
                    className={`absolute top-3 right-3 p-2 rounded-full shadow-md transition-all duration-200 ${isFavorited
                        ? 'bg-orange-500 text-white hover:bg-orange-600'
                        : 'bg-white/90 backdrop-blur-sm text-gray-600 hover:bg-white hover:text-orange-500'
                        }`}
                    title={isFavorited ? "Remove from favorites" : "Add to favorites"}
                >
                    <svg
                        xmlns="http://www.w3.org/2000/svg"
                        viewBox="0 0 24 24"
                        fill={isFavorited ? "currentColor" : "none"}
                        stroke="currentColor"
                        className="w-5 h-5"
                        strokeWidth="2"
                    >
                        <path strokeLinecap="round" strokeLinejoin="round" d="M17.593 3.322c1.1.128 1.907 1.077 1.907 2.185V21L12 17.25 4.5 21V5.507c0-1.108.806-2.057 1.907-2.185a48.507 48.507 0 0111.186 0z" />
                    </svg>
                </button>
            </div>
            <div className="p-5">
                <h3 className="text-xl font-bold text-gray-800 dark:text-gray-100 mb-2 line-clamp-1 group-hover:text-orange-600 dark:group-hover:text-orange-400 transition-colors">
                    {recipe.title}
                </h3>
                <p className="text-gray-600 dark:text-gray-400 text-sm mb-4 line-clamp-2 h-10">
                    {recipe.description || 'A delicious recipe waiting for you to try!'}
                </p>

                <div className="flex items-center gap-4 text-sm text-gray-500 dark:text-gray-400 mb-4">
                    <span className="flex items-center gap-1">
                        <span className="text-yellow-400">Γÿà</span>
                        {(() => {
                            const rating = recipe.average_rating || recipe.averageRating;
                            if (!rating && rating !== 0) return '0.0';
                            const numRating = typeof rating === 'number' ? rating : parseFloat(rating);
                            return isNaN(numRating) ? '0.0' : numRating.toFixed(1);
                        })()}
                    </span>
                    {(recipe.cooking_time || recipe.cookingTime) && (
