// API client for backend communication
const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000';

// Export API_BASE_URL for use in Google OAuth and other external redirects
export { API_BASE_URL };

const getAuthToken = () => {
  if (typeof window !== 'undefined') {
    return localStorage.getItem('token');
  }
  return null;
};

const getHeaders = (includeAuth = false) => {
  const headers = {
    'Content-Type': 'application/json',
  };

  if (includeAuth) {
    const token = getAuthToken();
    if (token) {
      headers['Authorization'] = `Bearer ${token}`;
    }
  }

  return headers;
};

export const api = {
  getRecipes: async (search = '', tag = '', limit = null) => {
    const params = new URLSearchParams();
    if (search) params.append('search', search);
    if (tag) params.append('tag', tag);
    if (limit) params.append('pageSize', limit);

    const url = `${API_BASE_URL}/api/recipes${params.toString() ? '?' + params.toString() : ''}`;
    const response = await fetch(url, {
      headers: getHeaders(true),
    });
    if (!response.ok) throw new Error('Failed to fetch recipes');
    const data = await response.json();

    // Filter out test recipes
    const isTestRecipe = (recipe) => {
      const username = recipe.author?.username || recipe.username || '';
      const title = recipe.title || '';

      const usernameLower = username.toLowerCase();
      const titleLower = title.toLowerCase();

      // 1. Filter out users that are clearly test users
      if (usernameLower.includes('test') ||
        usernameLower.includes('dummy') ||
        usernameLower.includes('mock')) {
        return true;
      }

      // 2. Filter out obvious "automated" test recipes
      // Matches "My Recipe 1234567890" or "Recipe 1234567890"
      if (/^(my )?recipe\s*\d{5,}/i.test(title)) {
        return true;
      }

      // Matches titles that are just a long number (timestamp)
      if (/^\d{10,}$/.test(title)) {
        return true;
      }

      // Matches "Test Recipe" or "Demo Recipe" exactly or with numbers
      if (/^(test|demo)\s*recipe/i.test(title)) {
        return true;
      }

      return false;
    };

    // Transform and filter recipes
    if (data.recipes && Array.isArray(data.recipes)) {
      return data.recipes
        .filter(recipe => !isTestRecipe(recipe))
        .map(recipe => ({
          id: recipe.id,
          title: recipe.title,
          description: recipe.description,
          image_url: recipe.imageUrl || recipe.image_url,
          cooking_time: recipe.cookingTime || recipe.cooking_time,
          servings: recipe.servings,
          average_rating: (() => {
            const rating = recipe.averageRating || recipe.average_rating;
            if (rating === null || rating === undefined) return 0;
            const numRating = typeof rating === 'number' ? rating : parseFloat(rating);
            return isNaN(numRating) ? 0 : numRating;
          })(),
          username: recipe.author?.username || recipe.username || 'Unknown',
          userId: recipe.author?.id || recipe.userId || recipe.user_id || null,
          tags: recipe.tags || []
        }));
    }
    return Array.isArray(data) ? data.filter(recipe => !isTestRecipe(recipe)) : [];
  },


  getPopularTags: async () => {
    const response = await fetch(`${API_BASE_URL}/api/recipes/tags/popular`, {
      headers: getHeaders(false),
    });
    if (!response.ok) throw new Error('Failed to fetch popular tags');
    const data = await response.json();
    return data.tags || [];
  },

  getRecipe: async (id) => {
    const response = await fetch(`${API_BASE_URL}/api/recipes/${id}`, {
      headers: getHeaders(true),
    });
    if (!response.ok) throw new Error('Failed to fetch recipe');
    const data = await response.json();

    if (data.recipe) {
      const recipe = data.recipe;
      return {
        id: recipe.id,
        title: recipe.title,
        description: recipe.description,
        image_url: recipe.imageUrl || recipe.image_url,
        cooking_time: recipe.cookingTime || recipe.cooking_time,
        servings: recipe.servings,
        average_rating: (() => {
          const rating = recipe.averageRating || recipe.average_rating;
          if (rating === null || rating === undefined) return 0;
          const numRating = typeof rating === 'number' ? rating : parseFloat(rating);
          return isNaN(numRating) ? 0 : numRating;
        })(),
        username: recipe.author?.username || recipe.username || 'Unknown',
        userId: recipe.author?.id || recipe.userId || recipe.user_id || null,
        ingredients: recipe.ingredients || [],
        steps: recipe.steps || [],
        reviews: (recipe.reviews || recipe.Reviews || []).map(review => ({
          id: review.id,
          comment: review.comment,
          rating: review.rating,
          createdAt: review.createdAt,
          User: review.User || review.user || {},
          username: review.User?.username || review.user?.username || review.username || 'Anonymous',
          userId: review.User?.id || review.user?.id || review.userId || null
        })),
        total_likes: recipe.totalLikes || recipe.total_likes || 0,
        isLiked: recipe.isLiked || false,
        isFavorited: recipe.isFavorited || false
      };
    }
    return data;
  },

  createRecipe: async (recipeData) => {
    const response = await fetch(`${API_BASE_URL}/api/recipes`, {
      method: 'POST',
      headers: getHeaders(true),
      body: JSON.stringify(recipeData),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.message || data.error || 'Failed to create recipe');

    // Handle Sequelize model format
    if (data.recipe) {
      if (!data.recipe.id) {
        if (data.recipe.dataValues && data.recipe.dataValues.id) {
          data.recipe.id = data.recipe.dataValues.id;
        } else if (data.recipe.get && typeof data.recipe.get === 'function') {
          try {
            data.recipe.id = data.recipe.get('id') || data.recipe.id;
          } catch (e) {
            console.warn('Could not extract id from Sequelize model:', e);
          }
        }
      }

      if (data.recipe.id && typeof data.recipe.id !== 'string') {
        data.recipe.id = String(data.recipe.id);
      }
    }

    return data;
  },

  register: async (username, email, password) => {
    const response = await fetch(`${API_BASE_URL}/api/users/register`, {
      method: 'POST',
      headers: getHeaders(false),
      body: JSON.stringify({ username, email, password }),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.error || data.message || 'Registration failed');
    return data;
  },

  login: async (email, password) => {
    const response = await fetch(`${API_BASE_URL}/api/users/login`, {
      method: 'POST',
      headers: getHeaders(false),
      body: JSON.stringify({ email, password }),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.error || data.message || 'Login failed');
    return data;
  },

  likeRecipe: async (recipeId) => {
    const response = await fetch(`${API_BASE_URL}/api/recipes/${recipeId}/like`, {
      method: 'POST',
      headers: getHeaders(true),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.message || data.error || 'Failed to like recipe');
    return data;
  },

  createComment: async (recipeId, comment, rating = null) => {
    const response = await fetch(`${API_BASE_URL}/api/recipes/${recipeId}/comments`, {
      method: 'POST',
      headers: getHeaders(true),
      body: JSON.stringify({ comment, rating }),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.message || data.error || 'Failed to create comment');
    return data;
  },

  updateComment: async (recipeId, commentId, comment, rating = null) => {
    const response = await fetch(`${API_BASE_URL}/api/recipes/${recipeId}/comments/${commentId}`, {
      method: 'PUT',
      headers: getHeaders(true),
      body: JSON.stringify({ comment, rating }),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.message || data.error || 'Failed to update comment');
    return data;
  },

  deleteComment: async (recipeId, commentId) => {
    const response = await fetch(`${API_BASE_URL}/api/recipes/${recipeId}/comments/${commentId}`, {
      method: 'DELETE',
      headers: getHeaders(true),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.message || data.error || 'Failed to delete comment');
    return data;
  },

  favoriteRecipe: async (recipeId) => {
    // Backend toggles favorite on POST
    const response = await fetch(`${API_BASE_URL}/api/recipes/${recipeId}/favourite`, {
      method: 'POST',
      headers: getHeaders(true),
    });

    // Verify JSON response
    const contentType = response.headers.get('content-type');
    if (!contentType || !contentType.includes('application/json')) {
      const text = await response.text();
      throw new Error(`Server returned non-JSON response. Status: ${response.status}. ${text.substring(0, 100)}`);
    }

    const data = await response.json();
    if (!response.ok) {
      throw new Error(data.message || data.error || 'Failed to toggle favorite');
    }
    return data;
  },

  unfavoriteRecipe: async (recipeId) => {
    // Same as favoriteRecipe - backend handles toggle
    const response = await fetch(`${API_BASE_URL}/api/recipes/${recipeId}/favourite`, {
      method: 'POST',
      headers: getHeaders(true),
    });

    const contentType = response.headers.get('content-type');
    if (!contentType || !contentType.includes('application/json')) {
      const text = await response.text();
      throw new Error(`Server returned non-JSON response. Status: ${response.status}. ${text.substring(0, 100)}`);
    }

    const data = await response.json();
    if (!response.ok) {
      throw new Error(data.message || data.error || 'Failed to toggle favorite');
    }
    return data;
  },

  updateRecipe: async (recipeId, recipeData) => {
    const response = await fetch(`${API_BASE_URL}/api/recipes/${recipeId}`, {
      method: 'PUT',
      headers: getHeaders(true),
      body: JSON.stringify(recipeData),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.message || data.error || 'Failed to update recipe');
    return data;
  },

  deleteRecipe: async (recipeId) => {
    const response = await fetch(`${API_BASE_URL}/api/recipes/${recipeId}`, {
      method: 'DELETE',
      headers: getHeaders(true),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.message || data.error || 'Failed to delete recipe');
    return data;
  },

  getUserProfile: async () => {
    const response = await fetch(`${API_BASE_URL}/api/users/profile`, {
      headers: getHeaders(true),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.message || data.error || 'Failed to fetch profile');
    return data.user || data;
  },

  getUserProfileById: async (userId) => {
    const response = await fetch(`${API_BASE_URL}/api/users/${userId}`, {
      headers: getHeaders(false), // Public endpoint
    });

    const contentType = response.headers.get('content-type');
    if (!contentType || !contentType.includes('application/json')) {
      const text = await response.text();
      throw new Error(`Server returned non-JSON response. Status: ${response.status}. ${text.substring(0, 100)}`);
    }

    const data = await response.json();
    if (!response.ok) {
      throw new Error(data.message || data.error || 'Failed to fetch user profile');
    }
    return data.user || data;
  },

  updateUserProfile: async (profileData) => {
    const response = await fetch(`${API_BASE_URL}/api/users/profile`, {
      method: 'PUT',
      headers: getHeaders(true),
      body: JSON.stringify(profileData),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.message || data.error || 'Failed to update profile');
    return data;
  },

  uploadProfilePicture: async (file) => {
    const formData = new FormData();
    formData.append('profilePicture', file);

    const token = getAuthToken();
    const headers = {};
    if (token) {
      headers['Authorization'] = `Bearer ${token}`;
    }

    const response = await fetch(`${API_BASE_URL}/api/users/profile/picture`, {
      method: 'PUT',
      headers,
      body: formData,
    });

    const contentType = response.headers.get('content-type');
    if (!contentType || !contentType.includes('application/json')) {
      const text = await response.text();
      throw new Error(`Server returned non-JSON response. Status: ${response.status}. ${text.substring(0, 100)}`);
    }

    const data = await response.json();

    if (response.status === 501) {
      throw new Error('Profile picture upload is not yet implemented on the backend. Please contact the development team.');
    }

    if (!response.ok) {
      throw new Error(data.message || data.error || 'Failed to upload profile picture');
    }
    return data;
  },

  uploadRecipeImage: async (file) => {
    const formData = new FormData();
    formData.append('recipeImage', file);

    const token = getAuthToken();
    const headers = {};
    if (token) {
      headers['Authorization'] = `Bearer ${token}`;
    }

    const response = await fetch(`${API_BASE_URL}/api/recipes/upload-image`, {
      method: 'POST',
      headers,
      body: formData,
    });

    const contentType = response.headers.get('content-type');
    if (!contentType || !contentType.includes('application/json')) {
      const text = await response.text();
      throw new Error(`Server returned non-JSON response. Status: ${response.status}. ${text.substring(0, 100)}`);
    }

    const data = await response.json();

    if (!response.ok) {
      throw new Error(data.message || data.error || 'Failed to upload recipe image');
    }
    return data;
  },

  getUserRecipes: async () => {
    const response = await fetch(`${API_BASE_URL}/api/users/recipes`, {
      headers: getHeaders(true),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.message || data.error || 'Failed to fetch user recipes');
    return Array.isArray(data.recipes) ? data.recipes : Array.isArray(data) ? data : [];
  },

  getUserFavorites: async () => {
    const response = await fetch(`${API_BASE_URL}/api/users/favorites`, {
      headers: getHeaders(true),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.message || data.error || 'Failed to fetch favorites');
    // Backend returns { recipes: [...] }
    return Array.isArray(data.recipes) ? data.recipes : Array.isArray(data) ? data : [];
  },

  updateUserPreferences: async (preferences) => {
    const response = await fetch(`${API_BASE_URL}/api/users/preferences`, {
      method: 'PUT',
      headers: getHeaders(true),
      body: JSON.stringify(preferences),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.message || data.error || 'Failed to update preferences');
    return data;
  },

  changePassword: async (currentPassword, newPassword) => {
    const response = await fetch(`${API_BASE_URL}/api/users/change-password`, {
      method: 'PUT',
      headers: getHeaders(true),
      body: JSON.stringify({ currentPassword, newPassword }),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.message || data.error || 'Failed to change password');
    return data;
  },

  googleLogin: async (token) => {
    const response = await fetch(`${API_BASE_URL}/api/users/google-login`, {
      method: 'POST',
      headers: getHeaders(false),
      body: JSON.stringify({ token }),
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.message || data.error || 'Google login failed');
    return data;
  },
};

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { api } from "@/lib/api";

export default function LoginPage() {
  const router = useRouter();

  // form state
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    // Check for token in URL (from Google Auth redirect)
    const params = new URLSearchParams(window.location.search);
    const token = params.get('token');
    const userData = params.get('user');
    const errorMsg = params.get('error');

    if (errorMsg) {
      setError('Google authentication failed. Please try again.');
      router.replace('/login'); // Clear URL params
    } else if (token && userData) {
      try {
        localStorage.setItem('token', token);
        localStorage.setItem('user', userData); // userData is already a JSON string from backend
        router.push('/');
      } catch (err) {
        console.error('Error parsing user data:', err);
        setError('Login failed');
      }
    }
  }, [router]);

  const handleGoogleLogin = () => {
    const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000';
    window.location.href = `${API_URL}/api/users/auth/google`;
  };

  async function handleSubmit(event) {
    event.preventDefault();
    setError("");

    if (!email || !password) {
      setError("Please provide both email and password.");
      return;
    }

    setLoading(true);

    try {
      const data = await api.login(email, password);
      if (data.token) {
        localStorage.setItem('token', data.token);
      }
      if (data.user) {
        localStorage.setItem('user', JSON.stringify(data.user));
      }
      router.push("/");
    } catch (err) {
      setError(err.message || "Login failed. Please check your credentials and try again.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <main className="min-h-screen flex items-center justify-center bg-gradient-to-b from-orange-50 to-white px-6">
      <div className="bg-white shadow-lg rounded-2xl p-8 w-full max-w-md">
        <h2 className="text-3xl font-bold text-center text-orange-600 mb-6">
          Login to TastyHub
        </h2>

        <form
          className="flex flex-col gap-4"
          onSubmit={handleSubmit}
          aria-describedby={error ? "login-error" : undefined}
        >
          {/* Email field: label is linked to input via htmlFor/id */}
          <div>
            <label htmlFor="email" className="block mb-1 font-medium text-gray-900">
              Email
            </label>
            <input
              id="email"
              name="email"
              type="email"
              className="w-full px-4 py-3 border border-gray-300 rounded-lg text-black focus:ring-2 focus:ring-orange-500 outline-none"
              placeholder="Enter your email"
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              aria-invalid={!!error}
            />
          </div>

          {/* Password field: label is linked to input via htmlFor/id */}
          <div>
            <label htmlFor="password" className="block mb-1 font-medium text-black">
              Password
            </label>
            <input
              id="password"
              name="password"
              type="password"
              className="w-full px-4 py-3 border border-gray-300 rounded-lg text-black focus:ring-2 focus:ring-orange-500 outline-none"
              placeholder="Enter your password"
              required
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              aria-invalid={!!error}
            />
          </div>

          <button
            type="submit"
            className="w-full bg-orange-500 text-white py-3 rounded-lg font-semibold hover:bg-orange-600 transition disabled:opacity-50"
            disabled={loading}
          >
            {loading ? "Logging in..." : "Login"}
          </button>

          <div className="relative flex py-2 items-center">
            <div className="flex-grow border-t border-gray-300"></div>
            <span className="flex-shrink-0 mx-4 text-gray-500 text-sm">Or continue with</span>
            <div className="flex-grow border-t border-gray-300"></div>
          </div>

          <button
            type="button"
            onClick={handleGoogleLogin}
            className="w-full bg-white border border-gray-300 text-gray-700 py-3 rounded-lg font-semibold hover:bg-gray-50 transition flex items-center justify-center gap-2"
            disabled={loading}
          >
            <img src="https://www.svgrepo.com/show/475656/google-color.svg" alt="Google" className="w-5 h-5" />
            Sign in with Google
          </button>

          {error && (
            <p id="login-error" role="alert" className="text-sm text-red-600 mt-2">
              {error}
            </p>
          )}
        </form>

        <p className="text-center text-gray-600 mt-4">
          Don&apos;t have an account?{" "}
          <a className="text-orange-600 font-medium hover:underline" href="/register">
            Register
          </a>
        </p>
      </div>
    </main>
  );
}

'use client';
import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import Navbar from "@/components/Navbar";
import Footer from "@/components/Footer";
import { api } from "@/lib/api";

export default function MyRecipesPage() {
  const router = useRouter();
  const [recipes, setRecipes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    const checkAuth = () => {
      const token = localStorage.getItem('token');
      if (!token) {
        router.push('/login?redirect=/my-recipes');
        return;
      }
      setIsAuthenticated(true);
      fetchRecipes();
    };

    checkAuth();
  }, [router]);

  const fetchRecipes = async () => {
    try {
      setLoading(true);
      const data = await api.getUserRecipes();
      setRecipes(data);
    } catch (err) {
      console.error('Error fetching recipes:', err);
      setError(err.message || 'Failed to load recipes');
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteRecipe = async (recipeId, recipeTitle) => {
    if (!confirm(`Are you sure you want to delete "${recipeTitle}"? This action cannot be undone.`)) {
      return;
    }

    try {
      await api.deleteRecipe(recipeId);
      // Remove recipe from list
      setRecipes(recipes.filter(r => r.id !== recipeId));
      setError('');
    } catch (err) {
      console.error('Error deleting recipe:', err);
      setError(err.message || 'Failed to delete recipe');
    }
  };

  if (!isAuthenticated) {
    return (
      <main className="min-h-screen bg-gradient-to-b from-orange-50 to-white dark:from-gray-900 dark:to-gray-800">
        <Navbar />
        <div className="flex-1 flex items-center justify-center py-20">
          <div className="text-orange-600 dark:text-orange-400 text-lg">Checking authentication...</div>
        </div>
        <Footer />
      </main>
    );
  }

  return (
    <main className="min-h-screen flex flex-col bg-gradient-to-b from-orange-50 to-white dark:from-gray-900 dark:to-gray-800">
      <Navbar />

      <div className="flex-1 max-w-6xl mx-auto px-6 py-12 w-full">
        <div className="flex flex-col items-center mb-10 text-center">
          <h1 className="text-4xl font-bold text-orange-600 dark:text-orange-400 mb-6">
            My Recipes
          </h1>
          <Link
            href="/recipes/new"
            className="px-8 py-3 bg-orange-500 text-white rounded-xl hover:bg-orange-600 transition font-semibold shadow-lg hover:shadow-orange-500/30 flex items-center gap-2"
          >
            <span>+</span> Create New Recipe
          </Link>
        </div>

        {error && (
          <div className="bg-red-100 dark:bg-red-900 border border-red-400 dark:border-red-600 text-red-700 dark:text-red-300 px-4 py-3 rounded mb-6">
            {error}
          </div>
        )}

        {loading ? (
          <div className="text-center py-20">
            <div className="text-orange-600 dark:text-orange-400 text-lg">Loading your recipes...</div>
          </div>
        ) : recipes.length === 0 ? (
          <div className="text-center py-20">
            <div className="text-6xl mb-4">≡ƒô¥</div>
            <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-200 mb-2">
              No recipes yet
            </h2>
            <p className="text-gray-600 dark:text-gray-400 mb-6">
              Start sharing your favorite recipes with the community!
            </p>
            <Link
              href="/recipes/new"
              className="inline-block px-6 py-3 bg-orange-500 text-white rounded-xl hover:bg-orange-600 transition font-semibold"
            >
              Create Your First Recipe
            </Link>
          </div>
        ) : (
          <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {recipes.map((recipe) => (
              <div
                key={recipe.id}
                className="bg-white dark:bg-gray-800 rounded-2xl shadow hover:shadow-lg transition overflow-hidden"
              >
                <Link href={`/recipes/${recipe.id}`}>
                  <img
                    src={recipe.imageUrl || recipe.image_url || '/placeholder-recipe.svg'}
                    alt={recipe.title}
                    className="w-full h-48 object-cover"
                  />
                </Link>
                <div className="p-5">
                  <Link href={`/recipes/${recipe.id}`}>
                    <h3 className="text-xl font-semibold text-gray-800 dark:text-gray-200 mb-2 hover:text-orange-600 dark:hover:text-orange-400 transition">
                      {recipe.title}
                    </h3>
                  </Link>
                  <p className="text-gray-600 dark:text-gray-400 text-sm mb-3 line-clamp-2">
                    {recipe.description || 'No description'}
                  </p>

                  <div className="flex items-center gap-4 text-sm text-gray-500 dark:text-gray-400 mb-4">
                    <span>Γ¡É {
                      (() => {
                        const rating = recipe.averageRating || recipe.average_rating;
                        if (!rating && rating !== 0) return 'No ratings';
                        const numRating = typeof rating === 'number' ? rating : parseFloat(rating);
                        return isNaN(numRating) ? 'No ratings' : numRating.toFixed(1);
                      })()
                    }</span>
                    {recipe.servings && <span>≡ƒæñ {recipe.servings}</span>}
                    {recipe.cookingTime && <span>ΓÅ▒∩╕Å {recipe.cookingTime}min</span>}
                  </div>

                  <div className="flex gap-2">
                    <Link
                      href={`/recipes/${recipe.id}`}
                      className="flex-1 text-center px-4 py-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition"
                    >
                      View
                    </Link>
                    <Link
                      href={`/recipes/${recipe.id}/edit`}
                      className="flex-1 text-center px-4 py-2 bg-gray-200 dark:bg-gray-700 text-gray-800 dark:text-gray-200 rounded-lg hover:bg-gray-300 dark:hover:bg-gray-600 transition"
                    >
                      Edit
                    </Link>
                    <button
                      onClick={() => handleDeleteRecipe(recipe.id, recipe.title)}
                      className="px-4 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition"
                    >
                      Delete
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      <Footer />
    </main>
  );
}

'use client';
import { useState, useEffect } from "react";
