'use client';
import { useState, useEffect } from "react";
import { useRouter, useParams } from "next/navigation";
import Link from "next/link";
import Navbar from "@/components/Navbar";
import Footer from "@/components/Footer";
import { api } from "@/lib/api";
import { compressImage } from "@/lib/imageUtils";

export default function EditRecipePage() {
  const router = useRouter();
  const params = useParams();
  const recipeId = params.id;

  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Recipe data
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [cookingTime, setCookingTime] = useState('');
  const [servings, setServings] = useState('');
  const [imageUrl, setImageUrl] = useState('');
  const [imageMode, setImageMode] = useState('url'); // 'url' or 'upload'
  const [uploadingImage, setUploadingImage] = useState(false);
  const [isPrivate, setIsPrivate] = useState(false);
  const [ingredientsText, setIngredientsText] = useState('');
  const [steps, setSteps] = useState([{ instruction: '' }]);

  // Tags
  const [tags, setTags] = useState([]);
  const [tagInput, setTagInput] = useState('');



  const handleImageUpload = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Validate file type
    if (!file.type.startsWith('image/')) {
      setError('Please select an image file');
      return;
    }

    // Validate file size (max 5MB)
    if (file.size > 5 * 1024 * 1024) {
      setError('Image size must be less than 5MB');
      return;
    }

    try {
      setUploadingImage(true);
      setError('');

      // Compress image before upload
      const compressedFile = await compressImage(file);

      const result = await api.uploadRecipeImage(compressedFile);
      setImageUrl(result.imageUrl);

    } catch (err) {
      console.error('Error uploading image:', err);
      setError(err.message || 'Failed to upload image');
    } finally {
      setUploadingImage(false);
    }
  };

  useEffect(() => {
    const checkAuth = () => {
      const token = localStorage.getItem('token');
      if (!token) {
        router.push(`/login?redirect=/recipes/${recipeId}/edit`);
        return;
      }
      setIsAuthenticated(true);
      fetchRecipe();
    };

    if (recipeId) {
      checkAuth();
    }
  }, [recipeId, router]);

  const fetchRecipe = async () => {
    try {
      setLoading(true);
      const recipe = await api.getRecipe(recipeId);

      // Populate form fields
      setTitle(recipe.title || '');
      setDescription(recipe.description || '');
      setCookingTime(recipe.cooking_time?.toString() || '');
      setServings(recipe.servings?.toString() || '');
      setImageUrl(recipe.image_url || '');
      setIsPrivate(recipe.isPrivate || recipe.is_private || false);

      // Convert ingredients to text
      if (recipe.ingredients && recipe.ingredients.length > 0) {
        const ingredientsText = recipe.ingredients
          .map(ing => {
            const name = ing.ingredientName || ing.name || '';
            const qty = ing.quantity;
            const unit = ing.unit;
            if (qty === 1 && unit === 'piece') {
              return name;
            }
            return `${qty} ${unit} ${name}`;
          })
          .join('\n');
        setIngredientsText(ingredientsText);
      }

      // Set steps
      if (recipe.steps && recipe.steps.length > 0) {
        setSteps(recipe.steps
          .sort((a, b) => (a.stepNumber || 0) - (b.stepNumber || 0))
          .map(step => ({ instruction: step.instruction || step.text || '' })));
      }

      // Set tags
      if (recipe.tags && Array.isArray(recipe.tags)) {
        setTags(recipe.tags);
      }
    } catch (err) {
      console.error('Error fetching recipe:', err);
      setError(err.message || 'Failed to load recipe');
    } finally {
      setLoading(false);
    }
  };

  const parseIngredients = (text) => {
    if (!text || !text.trim()) return [];

    const lines = text.split('\n')
      .map(line => line.trim())
      .filter(line => line.length > 0);

    return lines.map(line => ({
      name: line,
      quantity: 1,
      unit: 'piece',
      notes: null
    }));
  };

  const addStep = () => {
    setSteps([...steps, { instruction: '' }]);
  };

  const removeStep = (index) => {
    setSteps(steps.filter((_, i) => i !== index));
  };

  const updateStep = (index, value) => {
    const updated = [...steps];
    updated[index].instruction = value;
    setSteps(updated);
  };

  const addTag = () => {
    if (tagInput.trim() && !tags.includes(tagInput.trim())) {
      setTags([...tags, tagInput.trim()]);
      setTagInput('');
    }
  };

  const removeTag = (tagToRemove) => {
    setTags(tags.filter(tag => tag !== tagToRemove));
  };

  const handleTagKeyDown = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      addTag();
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSaving(true);

    const token = localStorage.getItem('token');
    if (!token) {
      setError('Please login to edit recipes');
      setSaving(false);
      router.push(`/login?redirect=/recipes/${recipeId}/edit`);
      return;
    }

    try {
      const parsedIngredients = parseIngredients(ingredientsText);

      const recipeData = {
        title: title.trim(),
        description: description.trim() || null,
        cookingTime: cookingTime ? parseInt(cookingTime) : null,
        servings: servings ? parseInt(servings) : null,
        imageUrl: imageUrl.trim() || null,
        isPrivate: isPrivate,
        tags: tags
      };

      await api.updateRecipe(recipeId, recipeData);

      // Success - redirect to recipe detail page
      router.push(`/recipes/${recipeId}`);
    } catch (err) {
      console.error('Update recipe error:', err);
      setError(err.message || 'Failed to update recipe. Please try again.');
    } finally {
      setSaving(false);
    }
  };

  if (loading || !isAuthenticated) {
    return (
      <main className="min-h-screen bg-gradient-to-b from-orange-50 to-white dark:from-gray-900 dark:to-gray-800">
        <Navbar />
        <div className="flex-1 flex items-center justify-center py-20">
          <div className="text-orange-600 dark:text-orange-400 text-lg">
            {loading ? 'Loading recipe...' : 'Checking authentication...'}
          </div>
        </div>
        <Footer />
      </main>
    );
  }

  return (
    <main className="min-h-screen flex flex-col bg-gradient-to-b from-orange-50 to-white dark:from-gray-900 dark:to-gray-800">
      <Navbar />

      <div className="flex-1 max-w-4xl mx-auto px-6 py-12 w-full">
        <Link href={`/recipes/${recipeId}`} className="text-orange-600 dark:text-orange-400 hover:underline mb-6 inline-block">
          ΓåÉ Back to Recipe
        </Link>

        <h1 className="text-4xl font-bold text-orange-600 dark:text-orange-400 mb-8 text-center">
          Edit Recipe
        </h1>

        {error && (
          <div className="bg-red-100 dark:bg-red-900 border border-red-400 dark:border-red-600 text-red-700 dark:text-red-300 px-4 py-3 rounded mb-6">
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg p-8">
          {/* Basic Information */}
          <section className="mb-8">
            <h2 className="text-2xl font-semibold text-gray-800 dark:text-gray-200 mb-4">Basic Information</h2>

            <div className="space-y-4">
              <div>
                <label className="block mb-1 font-medium text-gray-700 dark:text-gray-300">Recipe Title *</label>
                <input
                  type="text"
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  required
                  className="w-full px-4 py-3 border dark:border-gray-600 rounded-lg text-gray-900 dark:text-gray-100 dark:bg-gray-700 focus:ring-2 focus:ring-orange-500 outline-none"
                  placeholder="e.g., Chocolate Chip Cookies"
                />
              </div>

              <div>
                <label className="block mb-1 font-medium text-gray-700 dark:text-gray-300">Description</label>
                <textarea
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  rows={3}
                  className="w-full px-4 py-3 border dark:border-gray-600 rounded-lg text-gray-900 dark:text-gray-100 dark:bg-gray-700 focus:ring-2 focus:ring-orange-500 outline-none"
                  placeholder="Describe your recipe..."
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block mb-1 font-medium text-gray-700 dark:text-gray-300">Cooking Time (minutes)</label>
                  <input
                    type="number"
                    value={cookingTime}
                    onChange={(e) => setCookingTime(e.target.value)}
                    min="1"
                    className="w-full px-4 py-3 border dark:border-gray-600 rounded-lg text-gray-900 dark:text-gray-100 dark:bg-gray-700 focus:ring-2 focus:ring-orange-500 outline-none"
                    placeholder="30"
                  />
                </div>

                <div>
                  <label className="block mb-1 font-medium text-gray-700 dark:text-gray-300">Servings</label>
                  <input
                    type="number"
                    value={servings}
                    onChange={(e) => setServings(e.target.value)}
                    min="1"
                    className="w-full px-4 py-3 border dark:border-gray-600 rounded-lg text-gray-900 dark:text-gray-100 dark:bg-gray-700 focus:ring-2 focus:ring-orange-500 outline-none"
                    placeholder="4"
                  />
                </div>
              </div>

              <div>
                <label className="block mb-2 font-medium text-gray-700 dark:text-gray-300">Recipe Image</label>

                <div className="flex gap-4 mb-4">
                  <button
                    type="button"
                    onClick={() => setImageMode('url')}
                    className={`px-4 py-2 rounded-lg text-sm font-medium transition ${imageMode === 'url'
                      ? 'bg-orange-100 text-orange-700 border border-orange-200 dark:bg-orange-900/40 dark:text-orange-300 dark:border-orange-700'
                      : 'bg-gray-100 text-gray-600 hover:bg-gray-200 dark:bg-gray-700 dark:text-gray-300 dark:hover:bg-gray-600'
                      }`}
                  >
                    Image URL
                  </button>
                  <button
                    type="button"
                    onClick={() => setImageMode('upload')}
                    className={`px-4 py-2 rounded-lg text-sm font-medium transition ${imageMode === 'upload'
                      ? 'bg-orange-100 text-orange-700 border border-orange-200 dark:bg-orange-900/40 dark:text-orange-300 dark:border-orange-700'
                      : 'bg-gray-100 text-gray-600 hover:bg-gray-200 dark:bg-gray-700 dark:text-gray-300 dark:hover:bg-gray-600'
                      }`}
                  >
                    Upload Image
                  </button>
                </div>

                {imageMode === 'url' ? (
                  <input
                    type="url"
                    value={imageUrl}
                    onChange={(e) => setImageUrl(e.target.value)}
                    className="w-full px-4 py-3 border dark:border-gray-600 rounded-lg text-gray-900 dark:text-gray-100 dark:bg-gray-700 focus:ring-2 focus:ring-orange-500 outline-none"
                    placeholder="https://example.com/image.jpg"
                  />
                ) : (
                  <div className="border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-lg p-6 text-center hover:border-orange-400 dark:hover:border-orange-500 transition bg-gray-50 dark:bg-gray-700/50">
                    <input
                      type="file"
                      accept="image/*"
                      onChange={handleImageUpload}
                      disabled={uploadingImage}
                      className="hidden"
                      id="recipe-image-upload"
                    />
                    <label htmlFor="recipe-image-upload" className="cursor-pointer block">
                      {uploadingImage ? (
                        <div className="text-orange-600 dark:text-orange-400 font-medium">Uploading...</div>
                      ) : (
                        <>
                          <div className="text-4xl mb-2">≡ƒô╖</div>
                          <div className="text-gray-700 dark:text-gray-300 font-medium mb-1">Click to upload image</div>
                          <div className="text-sm text-gray-500 dark:text-gray-400">JPG, PNG, GIF up to 5MB</div>
                        </>
                      )}
                    </label>
                  </div>
                )}

                {imageUrl && (
                  <div className="mt-4 relative w-full h-48 bg-gray-100 dark:bg-gray-700 rounded-lg overflow-hidden border border-gray-200 dark:border-gray-600">
                    <img
                      src={imageUrl}
                      alt="Preview"
                      className="w-full h-full object-cover"
                      onError={(e) => { e.target.style.display = 'none'; }}
                    />
                  </div>
                )}
              </div>

              <div className="flex items-center gap-3">
                <input
                  type="checkbox"
                  id="isPrivate"
                  checked={isPrivate}
                  onChange={(e) => setIsPrivate(e.target.checked)}
                  className="w-5 h-5 text-orange-500 border-gray-300 dark:border-gray-600 rounded focus:ring-orange-500"
                />
                <label htmlFor="isPrivate" className="font-medium text-gray-700 dark:text-gray-300">
                  Make this recipe private (only visible to you)
                </label>
              </div>
            </div>
          </section>

          {/* Tags */}
          <section className="mb-8">
            <h2 className="text-2xl font-semibold text-gray-800 dark:text-gray-200 mb-4">Tags</h2>

            {/* Popular Tags Selection */}
            <div className="mb-4">
              <label className="block mb-2 font-medium text-gray-700 dark:text-gray-300">Popular Tags</label>
              <div className="flex flex-wrap gap-2">
                {['Italian', 'Dessert', 'Healthy', 'Quick', 'Breakfast', 'Vegan', 'Dinner', 'Spicy'].map((tag) => (
                  <button
                    key={tag}
                    type="button"
                    onClick={() => {
                      if (!tags.includes(tag)) {
                        setTags([...tags, tag]);
                      }
                    }}
                    className={`px-3 py-1 rounded-full text-sm font-medium border transition ${tags.includes(tag)
                      ? 'bg-orange-500 text-white border-orange-500'
                      : 'bg-white dark:bg-gray-700 text-gray-700 dark:text-gray-200 border-gray-300 dark:border-gray-600 hover:border-orange-500 hover:text-orange-500'
                      }`}
                  >
                    {tag}
                  </button>
                ))}
              </div>
            </div>

            <div className="mb-4">
              <label className="block mb-1 font-medium text-gray-700 dark:text-gray-300">Add Custom Tags</label>
              <div className="flex gap-2">
                <input
                  type="text"
                  value={tagInput}
                  onChange={(e) => setTagInput(e.target.value)}
                  onKeyDown={handleTagKeyDown}
                  className="flex-1 px-4 py-3 border dark:border-gray-600 rounded-lg text-gray-900 dark:text-gray-100 dark:bg-gray-700 focus:ring-2 focus:ring-orange-500 outline-none"
                  placeholder="e.g., Gluten-Free (Press Enter to add)"
                />
                <button
                  type="button"
                  onClick={addTag}
                  className="px-6 py-3 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition"
                >
                  Add
                </button>
              </div>
            </div>

            {tags.length > 0 && (
              <div className="flex flex-wrap gap-2">
                {tags.map((tag, index) => (
                  <span
                    key={index}
                    className="bg-orange-100 dark:bg-orange-900/40 text-orange-700 dark:text-orange-300 px-3 py-1 rounded-full text-sm font-medium flex items-center gap-2"
                  >
                    {tag}
                    <button
                      type="button"
                      onClick={() => removeTag(tag)}
                      className="text-orange-500 hover:text-orange-900 dark:hover:text-orange-200 font-bold"
                    >
                      ├ù
                    </button>
                  </span>
                ))}
              </div>
            )}
          </section>

          {/* Note about ingredients and steps */}
          <div className="bg-blue-50 dark:bg-blue-900 border border-blue-200 dark:border-blue-700 rounded-lg p-4 mb-6 text-sm text-blue-800 dark:text-blue-200">
            <strong>Note:</strong> Currently, you can only edit basic information. Full ingredient and step editing will be available soon.
          </div>

          {/* Submit Buttons */}
          <div className="flex gap-4 justify-end">
            <Link
              href={`/recipes/${recipeId}`}
              className="px-6 py-3 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 transition"
            >
              Cancel
            </Link>
            <button
              type="submit"
              disabled={saving}
              className="px-6 py-3 bg-orange-500 text-white rounded-lg font-semibold hover:bg-orange-600 transition disabled:opacity-50"
            >
              {saving ? 'Saving...' : 'Save Changes'}
            </button>
          </div>
        </form>
      </div>

      <Footer />
    </main>
  );
}

'use client';
/* eslint-disable @next/next/no-img-element */
import { useState, useEffect, useCallback } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import { api } from "@/lib/api";
import Navbar from "@/components/Navbar";
import Footer from "@/components/Footer";

export default function RecipeDetailPage() {
  const params = useParams();
  const router = useRouter();
  const recipeId = params.id;

  const [recipe, setRecipe] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Comment form state
  const [commentText, setCommentText] = useState('');
  const [commentRating, setCommentRating] = useState(5);
  const [submittingComment, setSubmittingComment] = useState(false);
  const [likeLoading, setLikeLoading] = useState(false);
  const [favoriteLoading, setFavoriteLoading] = useState(false);

  const fetchRecipe = useCallback(async () => {
    try {
      setLoading(true);
      const data = await api.getRecipe(recipeId);
      setRecipe(data);
    } catch (err) {
      console.error('Error fetching recipe:', err);
      setError(err.message || 'Failed to load recipe');
    } finally {
      setLoading(false);
    }
  }, [recipeId]);

  useEffect(() => {
    if (recipeId) {
      fetchRecipe();
    }
    const token = localStorage.getItem('token');
    setIsAuthenticated(!!token);
  }, [recipeId, fetchRecipe]);

  const handleLike = async () => {
    if (!isAuthenticated) {
      router.push(`/login?redirect=/recipes/${recipeId}`);
      return;
    }

    try {
      setLikeLoading(true);
      const result = await api.likeRecipe(recipeId);
      // Update recipe state with new like status
      setRecipe(prev => ({
        ...prev,
        isLiked: result.isLiked,
        total_likes: result.totalLikes
      }));
    } catch (err) {
      console.error('Error liking recipe:', err);
      alert(err.message || 'Failed to like recipe');
    } finally {
      setLikeLoading(false);
    }
  };

  const handleFavorite = async () => {
    if (!isAuthenticated) {
      router.push(`/login?redirect=/recipes/${recipeId}`);
      return;
    }

    try {
      setFavoriteLoading(true);
      const result = await api.favoriteRecipe(recipeId);
      setRecipe(prev => ({
        ...prev,
        isFavorited: result.isFavorited
      }));
    } catch (err) {
      console.error('Error favoriting recipe:', err);
      alert(err.message || 'Failed to update favorites');
    } finally {
      setFavoriteLoading(false);
    }
  };

  const handleSubmitComment = async (e) => {
    e.preventDefault();

    if (!isAuthenticated) {
      router.push(`/login?redirect=/recipes/${recipeId}`);
      return;
    }

    if (!commentText.trim()) {
      alert('Please enter a comment');
      return;
    }

    try {
      setSubmittingComment(true);
      const result = await api.createComment(recipeId, commentText.trim(), commentRating);

      // Refresh recipe to get updated reviews and rating
      await fetchRecipe();

      // Clear form
      setCommentText('');
      setCommentRating(5);
    } catch (err) {
      console.error('Error submitting comment:', err);
      alert(err.message || 'Failed to submit comment');
    } finally {
      setSubmittingComment(false);
    }
  };

  if (loading) {
    return (
      <main className="min-h-screen bg-gradient-to-b from-orange-50 to-white">
        <Navbar />
        <div className="flex-1 flex items-center justify-center py-20">
          <div className="text-orange-600 text-lg">Loading recipe...</div>
        </div>
      </main>
    );
  }

  if (error || !recipe) {
    return (
      <main className="min-h-screen bg-gradient-to-b from-orange-50 to-white">
        <Navbar />
        <div className="max-w-4xl mx-auto px-6 py-12">
          <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded mb-4">
            {error || 'Recipe not found'}
          </div>
          <Link href="/recipes" className="text-orange-600 hover:underline">
            ΓåÉ Back to Recipes
          </Link>
        </div>
      </main>
    );
  }

  return (
    <main className="min-h-screen bg-gradient-to-b from-orange-50 to-white dark:from-gray-900 dark:to-gray-800">
      <Navbar />

      <div className="max-w-4xl mx-auto px-6 py-12">
        {/* Back Button */}
        <Link href="/recipes" className="text-orange-600 hover:underline mb-6 inline-block">
          ΓåÉ Back to Recipes
        </Link>

        {/* Recipe Header */}
        <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg overflow-hidden mb-8">
          {recipe.image_url && (
            <img
              src={recipe.image_url}
              alt={recipe.title}
              className="w-full h-96 object-cover"
            />
          )}

          <div className="p-8">
            <h1 className="text-4xl font-bold text-gray-800 dark:text-gray-200 mb-4">{recipe.title}</h1>

            {recipe.description && (
              <p className="text-gray-600 dark:text-gray-400 text-lg mb-6">{recipe.description}</p>
            )}

            <div className="flex flex-wrap gap-6 text-gray-700 dark:text-gray-300 mb-4">
              {recipe.cooking_time && (
                <div className="flex items-center gap-2">
                  <span className="text-2xl">ΓÅ▒∩╕Å</span>
                  <span>{recipe.cooking_time} minutes</span>
                </div>
              )}
              {recipe.servings && (
                <div className="flex items-center gap-2">
                  <span className="text-2xl">≡ƒæñ</span>
                  <span>{recipe.servings} servings</span>
                </div>
              )}
              <div className="flex items-center gap-2">
                <span className="text-2xl">Γ¡É</span>
                <span>{(() => {
                  const rating = recipe.average_rating;
                  if (!rating && rating !== 0) return 'No ratings';
                  const numRating = typeof rating === 'number' ? rating : parseFloat(rating);
                  return isNaN(numRating) ? 'No ratings' : numRating.toFixed(1);
                })()}</span>
              </div>
              <div className="flex items-center gap-3 flex-wrap">
                <button
                  onClick={handleLike}
                  disabled={likeLoading}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg transition ${recipe.isLiked
                      ? 'bg-red-100 text-red-600 hover:bg-red-200'
                      : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                    } ${likeLoading ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}`}
                >
                  <span className="text-2xl">{recipe.isLiked ? 'Γ¥ñ∩╕Å' : '≡ƒñì'}</span>
                  <span>{recipe.total_likes || 0} likes</span>
                </button>
                <button
                  onClick={handleFavorite}
                  disabled={favoriteLoading}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg transition ${recipe.isFavorited
                      ? 'bg-pink-100 text-pink-600 hover:bg-pink-200'
                      : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                    } ${favoriteLoading ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}`}
                >
                  <span className="text-2xl">{recipe.isFavorited ? '≡ƒÆû' : '≡ƒñì'}</span>
                  <span>{recipe.isFavorited ? 'In favorites' : 'Add to favorites'}</span>
                </button>
              </div>
            </div>

            {/* Tags */}
            {recipe.tags && recipe.tags.length > 0 && (
              <div className="flex flex-wrap gap-2 mb-6">
                {recipe.tags.map((tag, index) => (
                  <Link
                    key={index}
                    href={`/recipes?search=${encodeURIComponent(tag)}`}
                    className="bg-orange-100 dark:bg-orange-900/40 text-orange-700 dark:text-orange-300 px-3 py-1 rounded-full text-sm font-medium hover:bg-orange-200 dark:hover:bg-orange-900/60 transition"
                  >
                    #{tag}
                  </Link>
                ))}
              </div>
            )}

            <div className="text-gray-600 dark:text-gray-400">
              By {recipe.userId ? (
                <Link
                  href={`/users/${recipe.userId}`}
                  className="font-semibold text-gray-800 dark:text-gray-200 hover:text-orange-600 dark:hover:text-orange-400 hover:underline"
                >
                  {recipe.username}
                </Link>
              ) : (
                <span className="font-semibold text-gray-800 dark:text-gray-200">{recipe.username}</span>
              )}
            </div>
          </div>
        </div>

        {/* Ingredients Section */}
        {recipe.ingredients && recipe.ingredients.length > 0 && (
          <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg p-8 mb-8">
            <h2 className="text-3xl font-bold text-gray-800 dark:text-gray-200 mb-6">Ingredients</h2>
            <ul className="space-y-3">
              {recipe.ingredients.map((ingredient, index) => {
                const ingredientName = ingredient.ingredientName || ingredient.name || '';
                const quantity = ingredient.quantity;
                const unit = ingredient.unit;
                // If quantity is 1 and unit is 'piece', just show the name
                const showQuantity = !(quantity === 1 && unit === 'piece');

                return (
                  <li key={index} className="flex items-start gap-3">
                    <span className="text-orange-500 mt-1">ΓÇó</span>
                    <span className="text-gray-700 dark:text-gray-300">
                      {showQuantity && `${quantity} ${unit} `}
                      <strong>{ingredientName}</strong>
                      {ingredient.notes && (
                        <span className="text-gray-500 dark:text-gray-400 italic"> ({ingredient.notes})</span>
                      )}
                    </span>
                  </li>
                );
              })}
            </ul>
          </div>
        )}

        {/* Instructions Section */}
        {recipe.steps && recipe.steps.length > 0 && (
          <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg p-8 mb-8">
            <h2 className="text-3xl font-bold text-gray-800 dark:text-gray-200 mb-6">Instructions</h2>
            <ol className="space-y-4">
              {recipe.steps
                .sort((a, b) => (a.stepNumber || 0) - (b.stepNumber || 0))
                .map((step, index) => (
                  <li key={index} className="flex gap-4">
                    <span className="flex-shrink-0 w-8 h-8 flex items-center justify-center bg-orange-500 text-white font-bold rounded-full">
                      {step.stepNumber || index + 1}
                    </span>
                    <p className="text-gray-700 dark:text-gray-300 flex-1 pt-1">
                      {step.instruction || step.text}
                    </p>
                  </li>
                ))}
            </ol>
          </div>
        )}

        {/* Comment Form */}
        {isAuthenticated && (
          <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg p-8 mb-8">
            <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-200 mb-4">Write a Review</h2>
            <form onSubmit={handleSubmitComment} className="space-y-4">
              <div>
                <label className="block mb-2 font-medium text-gray-700 dark:text-gray-300">Rating</label>
                <select
                  value={commentRating}
                  onChange={(e) => setCommentRating(parseInt(e.target.value))}
                  className="px-4 py-2 border dark:border-gray-600 rounded-lg text-gray-900 dark:text-white dark:bg-gray-700 focus:ring-2 focus:ring-orange-500 outline-none"
                >
                  <option value={5}>5 Γ¡ÉΓ¡ÉΓ¡ÉΓ¡ÉΓ¡É</option>
                  <option value={4}>4 Γ¡ÉΓ¡ÉΓ¡ÉΓ¡É</option>
                  <option value={3}>3 Γ¡ÉΓ¡ÉΓ¡É</option>
                  <option value={2}>2 Γ¡ÉΓ¡É</option>
                  <option value={1}>1 Γ¡É</option>
                </select>
              </div>
              <div>
                <label className="block mb-2 font-medium text-gray-700 dark:text-gray-300">Your Comment</label>
                <textarea
                  value={commentText}
                  onChange={(e) => setCommentText(e.target.value)}
                  rows={4}
                  className="w-full px-4 py-3 border dark:border-gray-600 rounded-lg text-gray-900 dark:text-white dark:bg-gray-700 focus:ring-2 focus:ring-orange-500 outline-none"
                  placeholder="Share your thoughts about this recipe..."
                  required
                />
              </div>
              <button
                type="submit"
                disabled={submittingComment}
                className="px-6 py-3 bg-orange-500 text-white rounded-lg font-semibold hover:bg-orange-600 transition disabled:opacity-50"
              >
                {submittingComment ? 'Submitting...' : 'Submit Review'}
              </button>
            </form>
          </div>
        )}

        {/* Reviews Section */}
        <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg p-8">
          <h2 className="text-3xl font-bold text-gray-800 dark:text-gray-200 mb-6">
            Reviews ({recipe.reviews?.length || 0})
          </h2>
          {recipe.reviews && recipe.reviews.length > 0 ? (
            <div className="space-y-6">
              {recipe.reviews.map((review, index) => {
                const reviewUser = review.User || review.user || {};
                const username = reviewUser.username || review.username || 'Anonymous';
                const userId = reviewUser.id || review.userId || review.user?.id || null;
                const rating = review.rating;
                const comment = review.comment;
                const createdAt = review.createdAt ? new Date(review.createdAt).toLocaleDateString() : '';

                return (
                  <div key={review.id || index} className="border-b border-gray-200 dark:border-gray-700 pb-6 last:border-0">
                    <div className="flex items-start justify-between mb-2">
                      <div className="flex items-center gap-3">
                        {userId ? (
                          <Link href={`/users/${userId}`} className="flex items-center gap-3 hover:opacity-80 transition">
                            <div className="w-10 h-10 rounded-full bg-orange-100 dark:bg-orange-900 flex items-center justify-center text-orange-600 dark:text-orange-400 font-bold overflow-hidden">
                              {reviewUser.profilePicture ? (
                                <img src={reviewUser.profilePicture} alt={username} className="w-full h-full object-cover" />
                              ) : (
                                username.charAt(0).toUpperCase()
                              )}
                            </div>
                            <div>
                              <div className="font-semibold text-gray-800 dark:text-gray-200 hover:text-orange-600 dark:hover:text-orange-400">{username}</div>
                              {createdAt && (
                                <div className="text-sm text-gray-500 dark:text-gray-400">{createdAt}</div>
                              )}
                            </div>
                          </Link>
                        ) : (
                          <>
                            <div className="w-10 h-10 rounded-full bg-orange-100 dark:bg-orange-900 flex items-center justify-center text-orange-600 dark:text-orange-400 font-bold">
                              {username.charAt(0).toUpperCase()}
                            </div>
                            <div>
                              <div className="font-semibold text-gray-800 dark:text-gray-200">{username}</div>
                              {createdAt && (
                                <div className="text-sm text-gray-500 dark:text-gray-400">{createdAt}</div>
                              )}
                            </div>
                          </>
                        )}
                      </div>
                      {rating && (
                        <div className="flex items-center gap-1">
                          <span className="text-yellow-500 text-xl">Γ¡É</span>
                          <span className="font-semibold text-gray-800 dark:text-gray-200">{rating}/5</span>
                        </div>
                      )}
                    </div>
                    {comment && (
                      <p className="text-gray-700 dark:text-gray-300 mt-2">{comment}</p>
                    )}
                  </div>
                );
              })}
            </div>
          ) : (
            <p className="text-gray-500 dark:text-gray-400 text-center py-8">No reviews yet. Be the first to review this recipe!</p>
          )}
        </div>
      </div>

      <Footer />
    </main>
  );
}

'use client';
import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { api } from "@/lib/api";
import { compressImage } from "@/lib/imageUtils";

export default function CreateRecipePage() {
  const router = useRouter();
  const [loading, setLoading] = useState(true); // Start with loading true to check auth
  const [error, setError] = useState('');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Recipe basic info
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [cookingTime, setCookingTime] = useState('');
  const [servings, setServings] = useState('');
  const [imageUrl, setImageUrl] = useState('');
  const [imageMode, setImageMode] = useState('url'); // 'url' or 'upload'
  const [uploadingImage, setUploadingImage] = useState(false);

  const handleImageUpload = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Validate file type
    if (!file.type.startsWith('image/')) {
      setError('Please select an image file');
      return;
    }

    // Validate file size (max 5MB)
    if (file.size > 5 * 1024 * 1024) {
      setError('Image size must be less than 5MB');
      return;
    }

    try {
      setUploadingImage(true);
      setError('');

      // Compress image before upload
      const compressedFile = await compressImage(file);

      const result = await api.uploadRecipeImage(compressedFile);
      setImageUrl(result.imageUrl);

    } catch (err) {
      console.error('Error uploading image:', err);
      setError(err.message || 'Failed to upload image');
    } finally {
      setUploadingImage(false);
    }
  };

  // Ingredients - simple text input
  const [ingredientsText, setIngredientsText] = useState('');

  // Steps
  const [steps, setSteps] = useState([
    { instruction: '' }
  ]);

  // Tags
  const [tags, setTags] = useState([]);
  const [tagInput, setTagInput] = useState('');

  // Check authentication on component mount
  useEffect(() => {
    const checkAuth = () => {
      const token = localStorage.getItem('token');
      if (!token) {
        // Redirect to login with return URL
        router.push('/login?redirect=/recipes/new');
        return;
      }
      setIsAuthenticated(true);
      setLoading(false);
    };

    checkAuth();
  }, [router]);

  // Don't render form if not authenticated or still checking
  if (loading || !isAuthenticated) {
    return (
      <main className="min-h-screen bg-gradient-to-b from-orange-50 to-white">
        <Navbar />
        <div className="flex-1 flex items-center justify-center py-20">
          <div className="text-orange-600 text-lg">Checking authentication...</div>
        </div>
      </main>
    );
  }

  // Parse ingredients text into array format for backend
  const parseIngredients = (text) => {
    if (!text || !text.trim()) return [];

    // Split by newlines and filter empty lines
    const lines = text.split('\n')
      .map(line => line.trim())
      .filter(line => line.length > 0);

    // Convert each line to an ingredient object
    // Each line becomes an ingredient with default quantity=1 and unit='piece'
    return lines.map(line => ({
      name: line,
      quantity: 1,
      unit: 'piece',
      notes: null
    }));
  };

  const addStep = () => {
    setSteps([...steps, { instruction: '' }]);
  };

  const removeStep = (index) => {
    setSteps(steps.filter((_, i) => i !== index));
  };

  const updateStep = (index, value) => {
    const updated = [...steps];
    updated[index].instruction = value;
    setSteps(updated);
  };

  const addTag = () => {
    if (tagInput.trim() && !tags.includes(tagInput.trim())) {
      setTags([...tags, tagInput.trim()]);
      setTagInput('');
    }
  };

  const removeTag = (tagToRemove) => {
    setTags(tags.filter(tag => tag !== tagToRemove));
  };

  const handleTagKeyDown = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      addTag();
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    // Double-check authentication before submitting
    const token = localStorage.getItem('token');
    if (!token) {
      setError('Please login to create a recipe');
      setLoading(false);
      router.push('/login?redirect=/recipes/new');
      return;
    }

    try {
      // Parse ingredients from text
      const parsedIngredients = parseIngredients(ingredientsText);

      // Prepare recipe data according to backend expectations
      const recipeData = {
        title: title.trim(),
        description: description.trim() || null,
        cookingTime: cookingTime ? parseInt(cookingTime) : null,
        servings: servings ? parseInt(servings) : null,
        imageUrl: imageUrl.trim() || null,
        ingredients: parsedIngredients,
        steps: steps
          .filter(step => step.instruction.trim())
          .map((step, index) => ({
            stepNumber: index + 1,
            instruction: step.instruction.trim()
          })),
        tags: tags
      };

      const result = await api.createRecipe(recipeData);

      // Redirect to the new recipe detail page
      // Backend returns { message: '...', recipe: {...} }
      if (result && result.recipe && result.recipe.id) {
        // Successfully created - redirect to recipe detail page
        router.push(`/recipes/${result.recipe.id}`);
      } else {
        console.error('Recipe ID not found in response:', result);
        setError('Recipe created successfully! Redirecting to recipes list...');
        // Fallback: redirect to recipes list after a short delay
        setTimeout(() => {
          router.push('/recipes');
        }, 2000);
      }
    } catch (err) {
      console.error('Create recipe error:', err);
      setError(err.message || 'Failed to create recipe. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <main className="min-h-screen bg-gradient-to-b from-orange-50 to-white">
      <Navbar />

      <div className="max-w-4xl mx-auto px-6 py-12">
        <h1 className="text-4xl font-bold text-orange-600 mb-8 text-center">Create New Recipe</h1>

        {error && (
          <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded mb-6">
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="bg-white rounded-2xl shadow-lg p-8">
          {/* Basic Information */}
          <section className="mb-8">
            <h2 className="text-2xl font-semibold text-gray-800 mb-4">Basic Information</h2>

            <div className="space-y-4">
              <div>
                <label className="block mb-1 font-medium text-gray-700">Recipe Title *</label>
                <input
                  type="text"
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  required
                  className="w-full px-4 py-3 border rounded-lg text-gray-900 focus:ring-2 focus:ring-orange-500 outline-none"
                  placeholder="e.g., Chocolate Chip Cookies"
                />
              </div>

              <div>
                <label className="block mb-1 font-medium text-gray-700">Description</label>
                <textarea
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  rows={3}
                  className="w-full px-4 py-3 border rounded-lg text-gray-900 focus:ring-2 focus:ring-orange-500 outline-none"
                  placeholder="Describe your recipe..."
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block mb-1 font-medium text-gray-700">Cooking Time (minutes)</label>
                  <input
                    type="number"
                    value={cookingTime}
                    onChange={(e) => setCookingTime(e.target.value)}
                    min="1"
                    className="w-full px-4 py-3 border rounded-lg text-gray-900 focus:ring-2 focus:ring-orange-500 outline-none"
                    placeholder="30"
                  />
                </div>

                <div>
                  <label className="block mb-1 font-medium text-gray-700">Servings</label>
                  <input
                    type="number"
                    value={servings}
                    onChange={(e) => setServings(e.target.value)}
                    min="1"
                    className="w-full px-4 py-3 border rounded-lg text-gray-900 focus:ring-2 focus:ring-orange-500 outline-none"
                    placeholder="4"
                  />
                </div>
              </div>

              <div>
                <label className="block mb-2 font-medium text-gray-700">Recipe Image</label>

                <div className="flex gap-4 mb-4">
                  <button
                    type="button"
                    onClick={() => setImageMode('url')}
                    className={`px-4 py-2 rounded-lg text-sm font-medium transition ${imageMode === 'url'
                      ? 'bg-orange-100 text-orange-700 border border-orange-200'
                      : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                      }`}
                  >
                    Image URL
                  </button>
                  <button
                    type="button"
                    onClick={() => setImageMode('upload')}
                    className={`px-4 py-2 rounded-lg text-sm font-medium transition ${imageMode === 'upload'
                      ? 'bg-orange-100 text-orange-700 border border-orange-200'
                      : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                      }`}
                  >
                    Upload Image
                  </button>
                </div>

                {imageMode === 'url' ? (
                  <input
                    type="url"
                    value={imageUrl}
                    onChange={(e) => setImageUrl(e.target.value)}
                    className="w-full px-4 py-3 border rounded-lg text-gray-900 focus:ring-2 focus:ring-orange-500 outline-none"
                    placeholder="https://example.com/image.jpg"
                  />
                ) : (
                  <div className="border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-orange-400 transition bg-gray-50">
                    <input
                      type="file"
                      accept="image/*"
                      onChange={handleImageUpload}
                      disabled={uploadingImage}
                      className="hidden"
                      id="recipe-image-upload"
                    />
                    <label htmlFor="recipe-image-upload" className="cursor-pointer block">
                      {uploadingImage ? (
                        <div className="text-orange-600 font-medium">Uploading...</div>
                      ) : (
                        <>
                          <div className="text-4xl mb-2">≡ƒô╖</div>
                          <div className="text-gray-700 font-medium mb-1">Click to upload image</div>
                          <div className="text-sm text-gray-500">JPG, PNG, GIF up to 5MB</div>
                        </>
                      )}
                    </label>
                  </div>
                )}

                {imageUrl && (
                  <div className="mt-4 relative w-full h-48 bg-gray-100 rounded-lg overflow-hidden border border-gray-200">
                    <img
                      src={imageUrl}
                      alt="Preview"
                      className="w-full h-full object-cover"
                      onError={(e) => { e.target.style.display = 'none'; }}
                    />
                  </div>
                )}
              </div>
            </div>
          </section>

          {/* Tags */}
          <section className="mb-8">
            <h2 className="text-2xl font-semibold text-gray-800 mb-4">Tags</h2>

            {/* Popular Tags Selection */}
            <div className="mb-4">
              <label className="block mb-2 font-medium text-gray-700">Popular Tags</label>
              <div className="flex flex-wrap gap-2">
                {['Italian', 'Dessert', 'Healthy', 'Quick', 'Breakfast', 'Vegan', 'Dinner', 'Spicy'].map((tag) => (
                  <button
                    key={tag}
                    type="button"
                    onClick={() => {
                      if (!tags.includes(tag)) {
                        setTags([...tags, tag]);
                      }
                    }}
                    className={`px-3 py-1 rounded-full text-sm font-medium border transition ${tags.includes(tag)
                      ? 'bg-orange-500 text-white border-orange-500'
                      : 'bg-white text-gray-700 border-gray-300 hover:border-orange-500 hover:text-orange-500'
                      }`}
                  >
                    {tag}
                  </button>
                ))}
              </div>
            </div>

            <div className="mb-4">
              <label className="block mb-1 font-medium text-gray-700">Add Custom Tags</label>
              <div className="flex gap-2">
                <input
                  type="text"
                  value={tagInput}
                  onChange={(e) => setTagInput(e.target.value)}
                  onKeyDown={handleTagKeyDown}
                  className="flex-1 px-4 py-3 border rounded-lg text-gray-900 focus:ring-2 focus:ring-orange-500 outline-none"
                  placeholder="e.g., Gluten-Free (Press Enter to add)"
                />
                <button
                  type="button"
                  onClick={addTag}
                  className="px-6 py-3 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition"
                >
                  Add
                </button>
              </div>
            </div>

            {tags.length > 0 && (
              <div className="flex flex-wrap gap-2">
                {tags.map((tag, index) => (
                  <span
                    key={index}
                    className="bg-orange-100 text-orange-700 px-3 py-1 rounded-full text-sm font-medium flex items-center gap-2"
                  >
                    {tag}
                    <button
                      type="button"
                      onClick={() => removeTag(tag)}
                      className="text-orange-500 hover:text-orange-900 font-bold"
                    >
                      ├ù
                    </button>
                  </span>
                ))}
              </div>
            )}
          </section>

          {/* Ingredients */}
          <section className="mb-8">
            <h2 className="text-2xl font-semibold text-gray-800 mb-4">Ingredients</h2>
            <div className="mb-2">
              <label className="block mb-1 font-medium text-gray-700">
                List ingredients (one per line)
              </label>
              <textarea
                value={ingredientsText}
                onChange={(e) => setIngredientsText(e.target.value)}
                rows={8}
                className="w-full px-4 py-3 border rounded-lg text-gray-900 focus:ring-2 focus:ring-orange-500 outline-none"
                placeholder="Enter ingredients, one per line:&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs&#10;1 tsp vanilla extract"
              />
              <p className="text-sm text-gray-500 mt-2">
                Enter each ingredient on a new line. You can include quantities and units if desired.
              </p>
            </div>
          </section>

          {/* Steps */}
          <section className="mb-8">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-2xl font-semibold text-gray-800">Instructions</h2>
              <button
                type="button"
                onClick={addStep}
                className="px-4 py-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition"
              >
                + Add Step
              </button>
            </div>

            <div className="space-y-3">
              {steps.map((step, index) => (
                <div key={index} className="flex gap-2">
                  <span className="flex-shrink-0 w-8 h-10 flex items-center justify-center bg-orange-100 text-orange-600 font-bold rounded-lg">
                    {index + 1}
                  </span>
                  <textarea
                    value={step.instruction}
                    onChange={(e) => updateStep(index, e.target.value)}
                    placeholder={`Step ${index + 1} instruction...`}
                    rows={2}
                    className="flex-1 px-4 py-2 border rounded-lg text-gray-900 focus:ring-2 focus:ring-orange-500 outline-none"
                  />
                  {steps.length > 1 && (
                    <button
                      type="button"
                      onClick={() => removeStep(index)}
                      className="px-3 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition"
                    >
                      Remove
                    </button>
                  )}
                </div>
              ))}
            </div>
          </section>

          {/* Submit Buttons */}
          <div className="flex gap-4 justify-end">
            <Link
              href="/recipes"
              className="px-6 py-3 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition"
            >
              Cancel
            </Link>
            <button
              type="submit"
              disabled={loading}
              className="px-6 py-3 bg-orange-500 text-white rounded-lg font-semibold hover:bg-orange-600 transition disabled:opacity-50"
            >
              {loading ? 'Creating...' : 'Create Recipe'}
            </button>
          </div>
        </form>
      </div>
    </main>
  );
}

