'use client';
/* eslint-disable @next/next/no-img-element */
import Link from "next/link";
import { useState, useEffect, Suspense } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { api } from "@/lib/api";
import Navbar from "@/components/Navbar";
import Footer from "@/components/Footer";
import RecipeCard from "@/components/RecipeCard";

function RecipesContent() {
  const searchParams = useSearchParams();
  const router = useRouter();

  const [recipes, setRecipes] = useState([]);
  const [suggestedRecipes, setSuggestedRecipes] = useState([]);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);
  const [currentSearchTerm, setCurrentSearchTerm] = useState('');

  useEffect(() => {
    const query = searchParams.get('search') || '';
    setSearch(query);
    setCurrentSearchTerm(query);
    fetchRecipes(query);
  }, [searchParams]);

  const fetchRecipes = async (searchTerm = '') => {
    setLoading(true);
    try {
      // Check for special filter
      const isUntaggedFilter = searchParams.get('filter') === 'untagged';
      const isOtherFilter = searchParams.get('filter') === 'other';

      let data;
      if (isOtherFilter) {
        // Fetch all recipes
        const allRecipes = await api.getRecipes('');

        // Calculate popular tags (must match Home page logic to be consistent)
        const allTags = allRecipes.flatMap(r => r.tags || []);
        const uniqueTags = [...new Set(allTags)].slice(0, 8);
        const defaultTags = ['Italian', 'Dessert', 'Healthy', 'Quick', 'Breakfast', 'Vegan', 'Dinner', 'Spicy'];
        const popularTags = [...new Set([...uniqueTags, ...defaultTags])].slice(0, 8);

        // Filter recipes: Keep if NO tags OR has at least one tag NOT in popularTags
        data = allRecipes.filter(recipe => {
          const recipeTags = recipe.tags || [];
          // If no tags, it's "other" (untagged)
          if (recipeTags.length === 0) return true;

          // If it has tags, check if ANY of them are NOT in the popular list
          // This ensures recipes with "Italian" AND "Mexican" show up in "Other" (because of Mexican)
          return recipeTags.some(tag => !popularTags.includes(tag));
        });

        // Set a display friendly search term for the UI
        setCurrentSearchTerm('Other Recipes');
      } else if (isUntaggedFilter) {
        // Fetch all recipes and filter client-side for now
        const allRecipes = await api.getRecipes('');
        data = allRecipes.filter(recipe => !recipe.tags || recipe.tags.length === 0);
        // Set a display friendly search term for the UI
        setCurrentSearchTerm('Untagged Recipes');
      } else {
        data = await api.getRecipes(searchTerm);
      }

      setRecipes(data);

      // If no results found and we were searching, fetch suggestions
      if (data.length === 0 && (searchTerm || isUntaggedFilter || isOtherFilter)) {
        const allData = await api.getRecipes('');
        // Filter out any that might somehow match (unlikely if search failed) and limit to 6
        setSuggestedRecipes(allData.slice(0, 6));
      } else {
        setSuggestedRecipes([]);
      }
    } catch (error) {
      console.error('Error fetching recipes:', error);
      setRecipes([]);
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    if (search.trim()) {
      router.push(`/recipes?search=${encodeURIComponent(search.trim())}`);
    } else {
      router.push('/recipes');
    }
  };

  const clearSearch = () => {
    setSearch('');
    router.push('/recipes');
  };

  if (loading) {
    return (
      <main className="min-h-screen flex flex-col bg-gradient-to-b from-orange-50 to-white dark:from-gray-900 dark:to-gray-800">
        <Navbar />
        <div className="flex-1 flex items-center justify-center">
          <div className="text-orange-600 dark:text-orange-400 text-lg animate-pulse">Loading recipes...</div>
        </div>
        <Footer />
      </main>
    );
  }

  return (
    <main className="min-h-screen flex flex-col bg-gradient-to-b from-orange-50 to-white dark:from-gray-900 dark:to-gray-800">
      <Navbar />

      {/* Header */}
      <section className="text-center py-16 px-6">
        <h2 className="text-4xl font-extrabold text-orange-600 dark:text-orange-400 mb-3">
          Discover Delicious Recipes
        </h2>
        <p className="text-gray-700 dark:text-gray-300 text-lg max-w-2xl mx-auto mb-6">
          Browse a variety of dishes shared by food lovers across the world.
        </p>
        <Link
          href="/recipes/new"
          className="inline-block px-6 py-3 bg-orange-500 text-white rounded-xl hover:bg-orange-600 transition font-semibold shadow-lg hover:shadow-orange-500/30"
        >
          + Create New Recipe
        </Link>
      </section>

      {/* Search bar */}
      <form onSubmit={handleSearch} className="max-w-md mx-auto mb-10 px-4">
        <div className="flex gap-2 relative">
          <input
            type="text"
            placeholder="Search recipes or tags..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="flex-1 px-4 py-3 pl-10 rounded-xl border border-gray-300 dark:border-gray-600 text-black dark:text-white dark:bg-gray-700 placeholder-gray-500 dark:placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-orange-400 dark:focus:ring-orange-500 shadow-sm"
          />
          <span className="absolute left-3 top-3.5 text-gray-400">≡ƒöì</span>
          <button
            type="submit"
            className="bg-orange-500 text-white px-6 py-2 rounded-xl hover:bg-orange-600 transition shadow-md"
          >
            Search
          </button>
        </div>
      </form>

      {/* No Results Message */}
      {recipes.length === 0 && currentSearchTerm && (
        <div className="max-w-4xl mx-auto px-6 mb-8 text-center">
          <div className="bg-orange-50 dark:bg-orange-900/20 border border-orange-200 dark:border-orange-800 rounded-xl p-8">
            <h3 className="text-xl font-semibold text-gray-800 dark:text-gray-200 mb-2">
              {currentSearchTerm === 'Other Recipes'
                ? 'No other recipes found (all recipes belong to popular categories).'
                : currentSearchTerm === 'Untagged Recipes'
                  ? 'No untagged recipes found.'
                  : <span>Sorry, no recipes found with this tag: <span className="text-orange-600 dark:text-orange-400">"{currentSearchTerm}"</span></span>
              }
            </h3>
            <p className="text-gray-600 dark:text-gray-400 mb-6">
              But don't worry! Here are some other delicious recipes you might like:
            </p>
            <button
              onClick={clearSearch}
              className="text-orange-500 hover:underline font-medium"
            >
              View all recipes
            </button>
          </div>
        </div>
      )}

      {/* Recipe Grid */}
      <section className="grid sm:grid-cols-2 lg:grid-cols-3 gap-8 max-w-6xl mx-auto px-6 pb-20">
        {recipes.length > 0 ? (
          recipes.map((recipe) => (
            <RecipeCard key={recipe.id} recipe={recipe} />
          ))
        ) : (
          /* Show suggested recipes if main list is empty */
          suggestedRecipes.map((recipe) => (
            <RecipeCard key={recipe.id} recipe={recipe} />
          ))
        )}
      </section>

      {recipes.length === 0 && suggestedRecipes.length === 0 && !currentSearchTerm && (
        <div className="text-center text-gray-600 dark:text-gray-400 py-12">
          <p className="text-xl">No recipes available yet. Be the first to create one!</p>
        </div>
      )}

      <Footer />
    </main>
  );
}

export default function RecipesPage() {
  return (
    <Suspense fallback={
      <div className="min-h-screen flex items-center justify-center bg-white dark:bg-gray-900">
        <div className="text-orange-600 text-lg">Loading...</div>
      </div>
    }>
      <RecipesContent />
    </Suspense>
  );
}

"use client";
import Link from "next/link";
import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { api } from "@/lib/api";

export default function RegisterPage() {
  const router = useRouter();
  const [username, setUsername] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [profilePicture, setProfilePicture] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    // Check for token in URL (from Google Auth redirect)
    const params = new URLSearchParams(window.location.search);
    const token = params.get('token');
    const userData = params.get('user');
    const errorMsg = params.get('error');

    if (errorMsg) {
      setError('Google authentication failed. Please try again.');
      router.replace('/register'); // Clear URL params
    } else if (token && userData) {
      try {
        localStorage.setItem('token', token);
        localStorage.setItem('user', userData);
        router.push('/');
      } catch (err) {
        console.error('Error parsing user data:', err);
        setError('Login failed');
      }
    }
  }, [router]);

  const handleGoogleLogin = () => {
    const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000';
    window.location.href = `${API_URL}/api/users/auth/google`;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (password !== confirmPassword) {
      setError("Passwords do not match");
      return;
    }

    setLoading(true);

    try {
      await api.register(username, email, password);

      try {
        const loginResponse = await api.login(email, password);
        if (loginResponse?.token) {
          localStorage.setItem('token', loginResponse.token);
        }
        if (loginResponse?.user) {
          localStorage.setItem('user', JSON.stringify(loginResponse.user));
        }

        if (profilePicture) {
          try {
            await api.uploadProfilePicture(profilePicture);
          } catch (uploadError) {
            console.error('Profile picture upload error:', uploadError);
          }
        }

        router.push('/');
      } catch (loginError) {
        console.error('Auto-login error:', loginError);
        router.push('/login');
      }
    } catch (err) {
      console.error('Registration error:', err);
      if (err.message.includes('fetch')) {
        setError('Failed to connect to server. Make sure the backend is running on port 5000.');
      } else {
        setError(err.message || 'An error occurred while registering');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <main className="min-h-screen flex items-center justify-center bg-gradient-to-b from-orange-50 to-white px-6">
      <div className="bg-white shadow-lg rounded-2xl p-8 w-full max-w-md">
        <h2 className="text-3xl font-bold text-center text-orange-600 mb-6">Create your account</h2>

        {error && (
          <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded mb-4">{error}</div>
        )}

        <form onSubmit={handleSubmit} className="flex flex-col gap-4">
          <div>
            <label className="block mb-1 font-medium text-gray-900">Username</label>
            <input type="text" value={username} onChange={(e) => setUsername(e.target.value)} required placeholder="Choose a username" className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 outline-none text-black" />
          </div>

          <div>
            <label className="block mb-1 font-medium text-black">Email</label>
            <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} required placeholder="you@example.com" className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 outline-none text-black" />
          </div>

          <div>
            <label className="block mb-1 font-medium text-black">Password</label>
            <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} required placeholder="Choose a secure password" className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 outline-none text-black" />
          </div>

          <div>
            <label className="block mb-1 font-medium text-black">Confirm Password</label>
            <input type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} required placeholder="Repeat password" className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 outline-none text-black" />
          </div>

          <div>
            <label className="block mb-1 font-medium text-black">Profile Picture (optional)</label>
            <input
              type="file"
              accept="image/*"
              onChange={(e) => setProfilePicture(e.target.files?.[0] || null)}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg text-sm text-black"
            />
          </div>

          <button type="submit" disabled={loading} className="w-full bg-orange-500 text-white py-3 rounded-lg font-semibold hover:bg-orange-600 transition disabled:opacity-50">{loading ? 'Creating...' : 'Create account'}</button>

          <div className="relative flex py-2 items-center">
            <div className="flex-grow border-t border-gray-300"></div>
            <span className="flex-shrink-0 mx-4 text-gray-500 text-sm">Or continue with</span>
            <div className="flex-grow border-t border-gray-300"></div>
          </div>

          <button
            type="button"
            onClick={handleGoogleLogin}
            className="w-full bg-white border border-gray-300 text-gray-700 py-3 rounded-lg font-semibold hover:bg-gray-50 transition flex items-center justify-center gap-2"
            disabled={loading}
          >
            <img src="https://www.svgrepo.com/show/475656/google-color.svg" alt="Google" className="w-5 h-5" />
            Sign in with Google
          </button>
        </form>

        <p className="text-center text-gray-900 mt-4">Already have an account? <Link href="/login" className="text-orange-600 font-medium hover:underline">Login</Link></p>
      </div>
    </main>
  );
}

'use client';
import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import Navbar from "@/components/Navbar";
import Footer from "@/components/Footer";
import { api } from "@/lib/api";
import { compressImage } from "@/lib/imageUtils";

export default function SettingsPage() {
  const router = useRouter();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Settings state
  const [darkMode, setDarkMode] = useState(false);
  const [units, setUnits] = useState('metric');
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [profilePicture, setProfilePicture] = useState('');
  const [uploadingPicture, setUploadingPicture] = useState(false);
  const [editingName, setEditingName] = useState(false);
  const [editingEmail, setEditingEmail] = useState(false);

  useEffect(() => {
    const checkAuth = () => {
      const token = localStorage.getItem('token');
      if (!token) {
        router.push('/login?redirect=/settings');
        return;
      }
      setIsAuthenticated(true);
      loadSettings();
    };

    checkAuth();
  }, [router]);

  const loadSettings = async () => {
    try {
      setLoading(true);

      // Load user profile
      const user = await api.getUserProfile();
      setUsername(user.username || '');
      setEmail(user.email || '');
      setProfilePicture(user.profilePicture || user.profile_picture || '');

      // Load preferences from localStorage (will sync with backend later)
      const savedDarkMode = localStorage.getItem('darkMode') === 'true';
      const savedUnits = localStorage.getItem('units') || 'metric';

      setDarkMode(savedDarkMode);
      setUnits(savedUnits);
    } catch (err) {
      console.error('Error loading settings:', err);
      setError('Failed to load settings');
    } finally {
      setLoading(false);
    }
  };

  const handleSaveProfile = async (e, field) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setSaving(true);

    try {
      const updateData = {};
      if (field === 'username') updateData.username = username;
      if (field === 'email') updateData.email = email;

      await api.updateUserProfile(updateData);
      setSuccess(`${field === 'username' ? 'Name' : 'Email'} updated successfully!`);
      if (field === 'username') setEditingName(false);
      if (field === 'email') setEditingEmail(false);

      // Update localStorage user data
      const userData = localStorage.getItem('user');
      if (userData) {
        const user = JSON.parse(userData);
        if (field === 'username') user.username = username;
        if (field === 'email') user.email = email;
        localStorage.setItem('user', JSON.stringify(user));
      }
    } catch (err) {
      console.error('Error updating profile:', err);
      setError(err.message || 'Failed to update profile');
    } finally {
      setSaving(false);
    }
  };

  const handleSavePreferences = async () => {
    setError('');
    setSuccess('');
    setSaving(true);

    try {
      // Save to localStorage first for immediate effect
      localStorage.setItem('darkMode', darkMode.toString());
      localStorage.setItem('units', units);

      // Apply dark mode immediately - ensure light mode by default
      if (darkMode) {
        document.documentElement.classList.add('dark');
      } else {
        // Explicitly remove dark class to ensure light mode
        document.documentElement.classList.remove('dark');
      }

      // Try to sync with backend if endpoint exists
      try {
        // Check if updateUserPreferences exists in api
        if (api.updateUserPreferences) {
          await api.updateUserPreferences({ darkMode, units });
        }
      } catch {
        // Backend sync is optional - preferences are saved locally
        console.log('Preferences saved locally. Backend sync not available.');
      }

      setSuccess('Preferences saved!');
    } catch (err) {
      console.error('Error saving preferences:', err);
      setError('Failed to save preferences');
    } finally {
      setSaving(false);
    }
  };

  const handleProfilePictureUpload = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Validate file type
    if (!file.type.startsWith('image/')) {
      setError('Please select an image file');
      return;
    }

    // Validate file size (max 5MB)
    if (file.size > 5 * 1024 * 1024) {
      setError('Image size must be less than 5MB');
      return;
    }

    try {
      setUploadingPicture(true);
      setError('');

      // Compress image before upload (smaller size for profile pics)
      const compressedFile = await compressImage(file, 500);

      const result = await api.uploadProfilePicture(compressedFile);

      // Update profile picture URL
      const newPictureUrl = result.profilePicture || result.profile_picture || result.url;
      setProfilePicture(newPictureUrl);

      // Update localStorage
      const userData = localStorage.getItem('user');
      if (userData) {
        const user = JSON.parse(userData);
        user.profilePicture = newPictureUrl;
        localStorage.setItem('user', JSON.stringify(user));
      }

      setSuccess('Profile picture uploaded successfully!');

      // Reload user profile to get updated picture
      try {
        const updatedUser = await api.getUserProfile();
        setProfilePicture(updatedUser.profilePicture || updatedUser.profile_picture || newPictureUrl);

        // Update localStorage
        const userData = localStorage.getItem('user');
        if (userData) {
          const user = JSON.parse(userData);
          user.profilePicture = updatedUser.profilePicture || updatedUser.profile_picture || newPictureUrl;
          localStorage.setItem('user', JSON.stringify(user));
        }
      } catch (profileErr) {
        console.error('Error reloading profile:', profileErr);
        // Continue anyway - picture is uploaded
      }
    } catch (err) {
      console.error('Error uploading profile picture:', err);
      // Show user-friendly error message
      if (err.message.includes('not yet implemented')) {
        setError('Profile picture upload is not yet available. This feature is coming soon!');
      } else {
        setError(err.message || 'Failed to upload profile picture. Please try again.');
      }
    } finally {
      setUploadingPicture(false);
    }
  };

  if (loading || !isAuthenticated) {
    return (
      <main className="min-h-screen bg-gradient-to-b from-orange-50 to-white dark:from-gray-900 dark:to-gray-800">
        <Navbar />
        <div className="flex-1 flex items-center justify-center py-20">
          <div className="text-orange-600 dark:text-orange-400 text-lg">
            {loading ? 'Loading settings...' : 'Checking authentication...'}
          </div>
        </div>
        <Footer />
      </main>
    );
  }

  return (
    <main className="min-h-screen flex flex-col bg-gradient-to-b from-orange-50 to-white dark:from-gray-900 dark:to-gray-800">
      <Navbar />

      <div className="flex-1 max-w-4xl mx-auto px-6 py-12 w-full">
        <h1 className="text-4xl font-bold text-orange-600 dark:text-orange-400 mb-8 text-center">
          Settings
        </h1>

        {error && (
          <div className="bg-red-100 dark:bg-red-900 border border-red-400 dark:border-red-600 text-red-700 dark:text-red-300 px-4 py-3 rounded mb-6">
            {error}
          </div>
        )}

        {success && (
          <div className="bg-green-100 dark:bg-green-900 border border-green-400 dark:border-green-600 text-green-700 dark:text-green-300 px-4 py-3 rounded mb-6">
            {success}
          </div>
        )}

        {/* Profile Settings */}
        <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg p-8 mb-6">
          <h2 className="text-2xl font-semibold text-gray-800 dark:text-gray-200 mb-6">Profile Settings</h2>

          {/* Profile Picture Upload */}
          <div className="mb-6">
            <label className="block mb-2 font-medium text-gray-700 dark:text-gray-300">Profile Picture</label>
            <div className="flex items-center gap-4">
              <div className="w-24 h-24 rounded-full bg-orange-100 dark:bg-orange-900 flex items-center justify-center overflow-hidden border-2 border-orange-200 dark:border-orange-700 relative">
                {profilePicture ? (
                  <img
                    src={profilePicture}
                    alt="Profile"
                    className="w-full h-full object-cover"
                    onError={(e) => {
                      e.target.style.display = 'none';
                      e.target.nextSibling.style.display = 'flex';
                    }}
                  />
                ) : null}
                <span className={`text-3xl font-bold text-orange-600 dark:text-orange-400 absolute inset-0 flex items-center justify-center ${profilePicture ? 'hidden' : 'flex'}`}>
                  {username.charAt(0).toUpperCase() || 'U'}
                </span>
                {uploadingPicture && (
                  <div className="absolute inset-0 bg-black/50 flex items-center justify-center">
                    <div className="w-6 h-6 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                  </div>
                )}
              </div>
              <div>
                <label className="cursor-pointer">
                  <span className="px-4 py-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition inline-block">
                    {uploadingPicture ? 'Uploading...' : 'Upload Picture'}
                  </span>
                  <input
                    type="file"
                    accept="image/*"
                    onChange={handleProfilePictureUpload}
                    disabled={uploadingPicture}
                    className="hidden"
                  />
                </label>
                <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
                  JPG, PNG or GIF. Max size 5MB
                </p>
              </div>
            </div>
          </div>

          <div className="space-y-8">
            {/* Username Update */}
            <div className="border-b dark:border-gray-700 pb-6">
              <div className="flex justify-between items-center mb-2">
                <label className="font-medium text-gray-700 dark:text-gray-300">Display Name</label>
                {!editingName && (
                  <button
                    onClick={() => setEditingName(true)}
                    className="text-orange-600 dark:text-orange-400 hover:underline text-sm font-medium"
                  >
                    Change Name
                  </button>
                )}
              </div>

              {!editingName ? (
                <p className="text-gray-900 dark:text-gray-100 text-lg">{username}</p>
              ) : (
                <form onSubmit={(e) => {
                  e.preventDefault();
                  handleSaveProfile(e, 'username');
                }} className="flex gap-4 animate-fade-in">
                  <input
                    type="text"
                    value={username}
                    onChange={(e) => setUsername(e.target.value)}
                    required
                    autoFocus
                    className="flex-1 px-4 py-3 border dark:border-gray-600 rounded-lg text-gray-900 dark:text-gray-100 dark:bg-gray-700 focus:ring-2 focus:ring-orange-500 outline-none"
                    placeholder="Your username"
                  />
                  <button
                    type="submit"
                    disabled={saving}
                    className="px-6 py-3 bg-orange-500 text-white rounded-lg font-semibold hover:bg-orange-600 transition disabled:opacity-50 whitespace-nowrap"
                  >
                    {saving ? 'Saving...' : 'Save'}
                  </button>
                  <button
                    type="button"
                    onClick={() => setEditingName(false)}
                    className="px-4 py-3 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg font-semibold hover:bg-gray-300 dark:hover:bg-gray-600 transition"
                  >
                    Cancel
                  </button>
                </form>
              )}
            </div>

            {/* Email Update */}
            <div>
              <div className="flex justify-between items-center mb-2">
                <label className="font-medium text-gray-700 dark:text-gray-300">Email Address</label>
                {!editingEmail && (
                  <button
                    onClick={() => setEditingEmail(true)}
                    className="text-orange-600 dark:text-orange-400 hover:underline text-sm font-medium"
                  >
                    Change Email
                  </button>
                )}
              </div>

              {!editingEmail ? (
                <p className="text-gray-900 dark:text-gray-100 text-lg">{email}</p>
              ) : (
                <form onSubmit={(e) => {
                  e.preventDefault();
                  handleSaveProfile(e, 'email');
                }} className="flex gap-4 animate-fade-in">
                  <input
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    required
                    autoFocus
                    className="flex-1 px-4 py-3 border dark:border-gray-600 rounded-lg text-gray-900 dark:text-gray-100 dark:bg-gray-700 focus:ring-2 focus:ring-orange-500 outline-none"
                    placeholder="your@email.com"
                  />
                  <button
                    type="submit"
                    disabled={saving}
                    className="px-6 py-3 bg-orange-500 text-white rounded-lg font-semibold hover:bg-orange-600 transition disabled:opacity-50 whitespace-nowrap"
                  >
                    {saving ? 'Saving...' : 'Save'}
                  </button>
                  <button
                    type="button"
                    onClick={() => setEditingEmail(false)}
                    className="px-4 py-3 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg font-semibold hover:bg-gray-300 dark:hover:bg-gray-600 transition"
                  >
                    Cancel
                  </button>
                </form>
              )}
            </div>
          </div>
        </div>

        {/* Security Settings */}
        <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg p-8 mb-6">
          <h2 className="text-2xl font-semibold text-gray-800 dark:text-gray-200 mb-6">Security</h2>
          <ChangePasswordForm />
        </div>

        {/* Preferences */}
        <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg p-8 mb-6">
          <h2 className="text-2xl font-semibold text-gray-800 dark:text-gray-200 mb-6">Preferences</h2>

          <div className="space-y-6">
            {/* Dark Mode */}
            <div className="flex items-center justify-between">
              <div>
                <label className="block font-medium text-gray-700 dark:text-gray-300 mb-1">
                  Dark Mode
                </label>
                <p className="text-sm text-gray-500 dark:text-gray-400">
                  Toggle between light and dark theme
                </p>
              </div>
              <button
                onClick={() => setDarkMode(!darkMode)}
                className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${darkMode ? 'bg-orange-500' : 'bg-gray-300'
                  }`}
              >
                <span
                  className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${darkMode ? 'translate-x-6' : 'translate-x-1'
                    }`}
                />
              </button>
            </div>

            {/* Units */}
            <div>
              <label className="block font-medium text-gray-700 dark:text-gray-300 mb-2">
                Measurement Units
              </label>
              <select
                value={units}
                onChange={(e) => setUnits(e.target.value)}
                className="w-full px-4 py-3 border dark:border-gray-600 rounded-lg text-gray-900 dark:text-gray-100 dark:bg-gray-700 focus:ring-2 focus:ring-orange-500 outline-none"
              >
                <option value="metric">Metric (grams, liters, Celsius)</option>
                <option value="imperial">Imperial (ounces, cups, Fahrenheit)</option>
              </select>
              <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
                Choose your preferred measurement system
              </p>
            </div>

            <div className="bg-yellow-50 dark:bg-yellow-900 border border-yellow-200 dark:border-yellow-700 rounded-lg p-4 text-sm text-yellow-800 dark:text-yellow-200 mb-4">
              <strong>Note:</strong> Preferences are currently saved locally. Backend sync will be available soon.
            </div>

            <button
              onClick={handleSavePreferences}
              className="px-6 py-3 bg-orange-500 text-white rounded-lg font-semibold hover:bg-orange-600 transition"
            >
              Save Preferences
            </button>
          </div>
        </div>

        {/* Quick Links */}
        <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg p-8">
          <h2 className="text-2xl font-semibold text-gray-800 dark:text-gray-200 mb-4">Quick Links</h2>
          <div className="flex flex-wrap gap-4">
            <Link
              href="/profile"
              className="px-4 py-2 bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-200 dark:hover:bg-gray-600 transition"
            >
              View Profile
            </Link>
            <Link
              href="/my-recipes"
              className="px-4 py-2 bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-200 dark:hover:bg-gray-600 transition"
            >
              My Recipes
            </Link>
            <Link
              href="/favorites"
              className="px-4 py-2 bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-200 dark:hover:bg-gray-600 transition"
            >
              Favorites
            </Link>
          </div>
        </div>
      </div>

      <Footer />
    </main >
  );
}

function ChangePasswordForm() {
  const [isEditing, setIsEditing] = useState(false);
  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage({ type: '', text: '' });

    if (newPassword !== confirmPassword) {
      setMessage({ type: 'error', text: 'New passwords do not match' });
      return;
    }

    if (newPassword.length < 8) {
      setMessage({ type: 'error', text: 'Password must be at least 8 characters long' });
      return;
    }

    setLoading(true);
    try {
      await api.changePassword(currentPassword, newPassword);
      setMessage({ type: 'success', text: 'Password changed successfully' });
      setCurrentPassword('');
      setNewPassword('');
      setConfirmPassword('');
      setTimeout(() => {
        setIsEditing(false);
        setMessage({ type: '', text: '' });
      }, 2000);
    } catch (err) {
      setMessage({ type: 'error', text: err.message || 'Failed to change password' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      <div className="flex justify-between items-center mb-4">
        <label className="font-medium text-gray-700 dark:text-gray-300">Password</label>
        {!isEditing && (
          <button
            onClick={() => setIsEditing(true)}
            className="text-orange-600 dark:text-orange-400 hover:underline text-sm font-medium"
          >
            Change Password
          </button>
        )}
      </div>

      {!isEditing ? (
        <p className="text-gray-500 dark:text-gray-400">ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó</p>
      ) : (
        <form onSubmit={handleSubmit} className="space-y-4 animate-fade-in bg-gray-50 dark:bg-gray-700/50 p-6 rounded-xl">
          {message.text && (
            <div className={`px-4 py-3 rounded ${message.type === 'success'
              ? 'bg-green-100 dark:bg-green-900 text-green-700 dark:text-green-300 border border-green-400 dark:border-green-600'
              : 'bg-red-100 dark:bg-red-900 text-red-700 dark:text-red-300 border border-red-400 dark:border-red-600'
              }`}>
              {message.text}
            </div>
          )}

          <div>
            <label className="block mb-1 font-medium text-gray-700 dark:text-gray-300">Current Password</label>
            <input
              type="password"
              value={currentPassword}
              onChange={(e) => setCurrentPassword(e.target.value)}
              required
              className="w-full px-4 py-3 border dark:border-gray-600 rounded-lg text-gray-900 dark:text-gray-100 dark:bg-gray-700 focus:ring-2 focus:ring-orange-500 outline-none"
            />
          </div>

          <div>
            <label className="block mb-1 font-medium text-gray-700 dark:text-gray-300">New Password</label>
            <input
              type="password"
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
              required
              minLength={8}
              className="w-full px-4 py-3 border dark:border-gray-600 rounded-lg text-gray-900 dark:text-gray-100 dark:bg-gray-700 focus:ring-2 focus:ring-orange-500 outline-none"
            />
          </div>

          <div>
            <label className="block mb-1 font-medium text-gray-700 dark:text-gray-300">Confirm New Password</label>
            <input
              type="password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              required
              minLength={8}
              className="w-full px-4 py-3 border dark:border-gray-600 rounded-lg text-gray-900 dark:text-gray-100 dark:bg-gray-700 focus:ring-2 focus:ring-orange-500 outline-none"
            />
          </div>

          <div className="flex gap-4">
            <button
              type="submit"
              disabled={loading}
              className="px-6 py-3 bg-orange-500 text-white rounded-lg font-semibold hover:bg-orange-600 transition disabled:opacity-50"
            >
              {loading ? 'Updating...' : 'Update Password'}
            </button>
            <button
              type="button"
              onClick={() => {
                setIsEditing(false);
                setMessage({ type: '', text: '' });
                setCurrentPassword('');
                setNewPassword('');
                setConfirmPassword('');
              }}
              className="px-6 py-3 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg font-semibold hover:bg-gray-300 dark:hover:bg-gray-600 transition"
            >
              Cancel
            </button>
          </div>
        </form>
      )}
    </div>
  );
}

'use client';
import { useState, useEffect } from 'react';
import { useParams } from 'next/navigation';
import Link from 'next/link';
import Navbar from '@/components/Navbar';
import Footer from '@/components/Footer';
import { api } from '@/lib/api';

export default function UserProfilePage() {
  const params = useParams();
  const userId = params.id;

  const [user, setUser] = useState(null);
  const [recipes, setRecipes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    if (userId) {
      fetchUserProfile();
      fetchUserRecipes();
    }
  }, [userId]);

  const fetchUserProfile = async () => {
    try {
      const userData = await api.getUserProfileById(userId);
      setUser(userData);
    } catch (err) {
      console.error('Error fetching user profile:', err);
      setError(err.message || 'Failed to load user profile');
    } finally {
      setLoading(false);
    }
  };

  const fetchUserRecipes = async () => {
    try {
      // Get all recipes and filter by userId
      const allRecipes = await api.getRecipes();
      // Filter recipes by userId if available, otherwise fallback to username
      const userRecipes = allRecipes.filter(recipe => {
        if (user?.id && recipe.userId) {
          return recipe.userId === user.id;
        }
        // Fallback to username matching
        const recipeUsername = recipe.author?.username || recipe.username || '';
        const profileUsername = user?.username || '';
        return recipeUsername.toLowerCase() === profileUsername.toLowerCase();
      });
      setRecipes(userRecipes);
    } catch (err) {
      console.error('Error fetching user recipes:', err);
    }
  };

  useEffect(() => {
    if (user) {
      fetchUserRecipes();
    }
  }, [user]);

  if (loading) {
    return (
      <main className="min-h-screen flex flex-col bg-gradient-to-b from-orange-50 to-white dark:from-gray-900 dark:to-gray-800">
        <Navbar />
        <div className="flex-1 flex items-center justify-center py-20">
          <div className="text-orange-600 dark:text-orange-400 text-lg">Loading profile...</div>
        </div>
        <Footer />
      </main>
    );
  }

  if (error || !user) {
    return (
      <main className="min-h-screen flex flex-col bg-gradient-to-b from-orange-50 to-white dark:from-gray-900 dark:to-gray-800">
        <Navbar />
        <div className="max-w-4xl mx-auto px-6 py-12">
          <div className="bg-red-100 dark:bg-red-900 border border-red-400 dark:border-red-600 text-red-700 dark:text-red-300 px-4 py-3 rounded mb-4">
            {error || 'User not found'}
          </div>
          <Link href="/recipes" className="text-orange-600 dark:text-orange-400 hover:underline">
            ΓåÉ Back to Recipes
          </Link>
        </div>
        <Footer />
      </main>
    );
  }

  return (
    <main className="min-h-screen flex flex-col bg-gradient-to-b from-orange-50 to-white dark:from-gray-900 dark:to-gray-800">
      <Navbar />

      <div className="flex-1 max-w-4xl mx-auto px-6 py-12 w-full">
        <Link href="/recipes" className="text-orange-600 dark:text-orange-400 hover:underline mb-6 inline-block">
          ΓåÉ Back to Recipes
        </Link>

        <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg p-8 mb-6">
          <div className="flex flex-col md:flex-row items-center md:items-start gap-6">
            {/* Profile Picture */}
            <div className="w-32 h-32 rounded-full bg-orange-100 dark:bg-orange-900 flex items-center justify-center text-4xl font-bold text-orange-600 dark:text-orange-400 overflow-hidden border-4 border-orange-300 dark:border-orange-700 shadow-lg">
              {user?.profilePicture ? (
                <img
                  src={user.profilePicture}
                  alt={user.username}
                  className="w-full h-full rounded-full object-cover"
                  onError={(e) => {
                    e.target.style.display = 'none';
                    const parent = e.target.parentElement;
                    const initial = parent.querySelector('.profile-initial');
                    if (initial) initial.style.display = 'flex';
                  }}
                />
              ) : null}
              <span className={`profile-initial ${user?.profilePicture ? 'hidden' : 'flex'}`}>
                {user?.username?.charAt(0).toUpperCase() || 'U'}
              </span>
            </div>

            {/* User Info */}
            <div className="flex-1 text-center md:text-left">
              <h1 className="text-3xl font-bold text-gray-800 dark:text-gray-200 mb-2">
                {user.username || 'User'}
              </h1>
              {user.createdAt && (
                <p className="text-sm text-gray-500 dark:text-gray-400">
                  Member since {new Date(user.createdAt).toLocaleDateString()}
                </p>
              )}
            </div>
          </div>
        </div>

        {/* User's Recipes */}
        <div className="mb-6">
          <h2 className="text-2xl font-bold text-gray-800 dark:text-gray-200 mb-4">
            Recipes by {user.username}
          </h2>

          {recipes.length === 0 ? (
            <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg p-8 text-center">
              <p className="text-gray-600 dark:text-gray-400">
                This user hasn't shared any recipes yet.
              </p>
            </div>
          ) : (
            <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {recipes.map((recipe) => (
                <Link
                  key={recipe.id}
                  href={`/recipes/${recipe.id}`}
                  className="bg-white dark:bg-gray-800 rounded-2xl shadow hover:shadow-lg transition overflow-hidden block"
                >
                  <img
                    src={recipe.image_url || recipe.imageUrl || '/placeholder-recipe.svg'}
                    alt={recipe.title}
                    className="w-full h-48 object-cover"
                  />
                  <div className="p-5">
                    <h3 className="text-xl font-semibold text-gray-800 dark:text-gray-200 mb-2">
                      {recipe.title}
                    </h3>
                    <p className="text-gray-600 dark:text-gray-400 text-sm mb-3 line-clamp-2">
                      {recipe.description || 'No description'}
                    </p>
                    <div className="flex items-center gap-4 text-sm text-gray-500 dark:text-gray-400">
                      <span>Γ¡É {
                        (() => {
                          const rating = recipe.average_rating || recipe.averageRating;
                          if (!rating && rating !== 0) return 'No ratings';
                          const numRating = typeof rating === 'number' ? rating : parseFloat(rating);
                          return isNaN(numRating) ? 'No ratings' : numRating.toFixed(1);
                        })()
                      }</span>
                    </div>
                  </div>
                </Link>
              ))}
            </div>
          )}
        </div>
      </div>

      <Footer />
    </main>
  );
}
